﻿using NeeLaboratory.IO;
using NeeLaboratory.Runtime.Serialization;
using System.Collections.Generic;
using System.IO;
using System.IO.Pipes;
using System.Threading;
using System.Threading.Tasks;

namespace NeeLaboratory.Remote
{
    public class SimpleClient
    {
        private readonly string _serverPipeName;
        private readonly SemaphoreSlim _semaphore = new(1);


        public SimpleClient(string serverPipeName)
        {
            _serverPipeName = serverPipeName;
        }

        public async ValueTask<List<Chunk>> CallAsync(List<Chunk> args, CancellationToken token)
        {
            // セマフォで排他処理。通信は同時に１つだけ
            _semaphore.Wait(token);
            try
            {
                // 接続 2 秒タイムアウト
                return await CallInnerAsync(args, 2000, token);
            }
            finally
            {
                _semaphore.Release();
            }
        }

        public async ValueTask<List<Chunk>> CallInnerAsync(List<Chunk> args, int timeout, CancellationToken token)
        {
            ////Debug.WriteLine($"Client: Start");
            using (var pipeClient = new NamedPipeClientStream(".", _serverPipeName, PipeDirection.InOut))
            {
                ////Debug.WriteLine($"Client: Connect {_serverPipeName} ...");
                await pipeClient.ConnectAsync(timeout, token);

                using (var stream = new ChunkStream(pipeClient, true))
                {
                    // call
                    ////Debug.WriteLine($"Client: Call: {args[0].Id}");
                    stream.WriteChunkArray(args);

                    // result
                    var result = await stream.ReadChunkArrayAsync(token);
                    ////Debug.WriteLine($"Client: Result.Id: {result[0].Id}");

                    if (result[0].Id < 0)
                    {
                        var data = result[0].Data;
                        var message = data != null ? DefaultSerializer.Deserialize<string>(data, BasicJsonSerializerContext.Default) : "Susie Exception";
                        throw new IOException(message);
                    }

                    return result;
                }
            }
        }
    }
}

﻿using NeeLaboratory.IO;
using NeeLaboratory.Runtime.Serialization;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO.Pipes;

namespace NeeLaboratory.Remote
{
    public class SimpleServer
    {
        public delegate List<Chunk> SimpleReceiver(List<Chunk> chunks);

        private readonly string _name;

        private readonly Dictionary<int, SimpleReceiver> _receivers = new();

        public SimpleServer(string name)
        {
            _name = name;
        }

        public void AddReceiver(int id, SimpleReceiver receiver)
        {
            _receivers.Add(id, receiver);
        }

        public void ServerProcess()
        {
            while (true)
            {
                ServerProcessTurn();
                GC.Collect();
            }
        }

        public void ServerProcessTurn()
        {
            ////Trace.WriteLine($"Server: Open");
            using (var pipeServer = new NamedPipeServerStream(_name, PipeDirection.InOut))
            {
                ////Trace.WriteLine($"Server: Wait for connect...");
                pipeServer.WaitForConnection();

                using (var stream = new ChunkStream(pipeServer, true))
                {
                    var command = stream.ReadChunkArray();
                    var result = CommandExecute(command);
                    stream.WriteChunkArray(result);
                }
            }

            ////Trace.WriteLine($"Server: Closed");
        }

        private List<Chunk> CommandExecute(List<Chunk> command)
        {
            try
            {
                ////Trace.WriteLine($"Server: Execute: ChunkCount={command.Count} CommandId={command[0].Id}");
                var result = _receivers[command[0].Id].Invoke(command);
                ////Trace.WriteLine($"Server: Result: ChunkCount={result.Count}");
                return result;
            }
            catch (Exception ex)
            {
                Trace.WriteLine($"Server: Execute.Exception: " + ex.Message);
                Trace.Indent();
                Trace.WriteLine(ex);
                Trace.Unindent();
                return new List<Chunk>() { new Chunk(-1, DefaultSerializer.Serialize(ex.Message, BasicJsonSerializerContext.Default)) };
            }
        }

    }

}

