namespace NeeLaboratory.ComponentModel
{
    public class DisposableCollection : List<IDisposable>, IDisposable
    {
        private bool _disposedValue;

        protected virtual void Dispose(bool disposing)
        {
            if (!_disposedValue)
            {
                if (disposing)
                {
                    foreach (var disposable in this.Reverse<IDisposable>())
                    {
                        disposable.Dispose();
                    }
                }

                _disposedValue = true;
            }
        }

        public void Dispose()
        {
            Dispose(disposing: true);
            GC.SuppressFinalize(this);
        }


        public void Add(Action action)
        {
            Add(new AnonymousDisposable(action));
        }

        /// <summary>
        /// Clear disposable items and initialize this disposed flag.
        /// </summary>
        /// <remarks>
        /// overwrite Clear()
        /// </remarks>
        public new void Clear()
        {
            base.Clear();
            _disposedValue = false;
        }


#if false
        public static DisposableCollection operator +(DisposableCollection a, IDisposable b)
        {
            a.Add(b);
            return a;
        }

        public static DisposableCollection operator -(DisposableCollection a, IDisposable b)
        {
            a.Remove(b);
            return a;
        }
#endif
    }
}

﻿using System;
using System.ComponentModel;
using System.Threading;
using System.Threading.Tasks;

namespace NeeLaboratory.ComponentModel
{
    public static class NotifyPropertyChangedExtensions
    {
        /// <summary>
        /// 特定のプロパティが条件を満たすまで待機します
        /// </summary>
        public static async ValueTask WaitPropertyAsync<T>(this T source, string propertyName, Func<T, bool> condition, CancellationToken cancellationToken = default)
            where T : INotifyPropertyChanged
        {
            cancellationToken.ThrowIfCancellationRequested();

            if (condition(source)) return;

            var tcs = new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);

            PropertyChangedEventHandler handler = (sender, e) =>
            {
                if (e.PropertyName == propertyName && condition(source))
                {
                    tcs.TrySetResult(true);
                }
            };

            using (cancellationToken.Register(() => tcs.TrySetCanceled()))
            {
                try
                {
                    source.PropertyChanged += handler;
                    await tcs.Task;
                }
                finally
                {
                    source.PropertyChanged -= handler;
                }
            }
        }
    }
}

