﻿using System;
using System.Threading;
using System.Threading.Tasks;

namespace NeeLaboratory.Threading.Tasks
{
    public static class WaitHandleExtensions
    {
        /// <summary>
        /// WaitHandle待ちのタスク化。
        /// </summary>
        /// <example>
        /// await ManualResetEventSlim.WaitHandle.AsTask();
        /// </example>
        /// <remarks>
        /// https://docs.microsoft.com/ja-jp/dotnet/standard/asynchronous-programming-patterns/interop-with-other-asynchronous-patterns-and-types
        /// </remarks>
        public static Task AsTask(this WaitHandle waitHandle)
        {
            if (waitHandle == null) throw new ArgumentNullException(nameof(waitHandle));

            var tcs = new TaskCompletionSource<bool>();
            var rwh = ThreadPool.RegisterWaitForSingleObject(waitHandle, delegate { tcs.TrySetResult(true); }, null, -1, true);
            var t = tcs.Task;
            t.ContinueWith((antecedent) => rwh.Unregister(null));
            return t;
        }

        /// <summary>
        /// WaitHandle待ちのタスク化。
        /// AsTask().WaitAsync() を使ったほうが安全かも？
        /// </summary>
        /// <remarks>
        /// https://stackoverflow.com/questions/18756354/wrapping-manualresetevent-as-awaitable-task
        /// </remarks>
        public static Task WaitOneAsync(this WaitHandle waitHandle, CancellationToken cancellationToken, int timeoutMilliseconds = Timeout.Infinite)
        {
            if (waitHandle == null)
                throw new ArgumentNullException(nameof(waitHandle));

            var tcs = new TaskCompletionSource<bool>();
            CancellationTokenRegistration ctr = cancellationToken.Register(() => tcs.TrySetCanceled(cancellationToken));
            TimeSpan timeout = timeoutMilliseconds > Timeout.Infinite ? TimeSpan.FromMilliseconds(timeoutMilliseconds) : Timeout.InfiniteTimeSpan;

            RegisteredWaitHandle rwh = ThreadPool.RegisterWaitForSingleObject(waitHandle,
                (_, timedOut) =>
                {
                    if (timedOut)
                    {
                        tcs.TrySetCanceled();
                    }
                    else
                    {
                        tcs.TrySetResult(true);
                    }
                },
                null, timeout, true);

            Task<bool> task = tcs.Task;

            _ = task.ContinueWith(s =>
            {
                rwh.Unregister(null);
                return ctr.Unregister();
            }, CancellationToken.None);

            return task;
        }
    }

}

﻿using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using NeeLaboratory.SourceGenerator.Tools;
using System;
using System.Diagnostics;
using System.Linq;

namespace NeeLaboratory.SourceGenerator;

[Generator]
public sealed class LocalDebugGenerator : IIncrementalGenerator
{
    private static readonly string _generatorNamespace = "NeeLaboratory.Generators";

    public void Initialize(IncrementalGeneratorInitializationContext context)
    {
        context.RegisterPostInitializationOutput(static context =>
        {
            context.AddSource("LocalDebugAttribute.g.cs", $$"""
            using System;
            namespace {{_generatorNamespace}};

            [AttributeUsage(AttributeTargets.Class | AttributeTargets.Struct, AllowMultiple = false, Inherited = false)]
            internal sealed class LocalDebugAttribute : Attribute
            {
            }
            """);
        });

        var source = context.SyntaxProvider.ForAttributeWithMetadataName(
            $"{_generatorNamespace}.LocalDebugAttribute",
            static (node, token) => true,
            static (context, token) => context);

        context.RegisterSourceOutput(source, Emit);
    }

    static void Emit(SourceProductionContext context, GeneratorAttributeSyntaxContext source)
    {
        var typeSymbol = (INamedTypeSymbol)source.TargetSymbol;
        //var typeNode = (TypeDeclarationSyntax)source.TargetNode;

        var ns = typeSymbol.ContainingNamespace.IsGlobalNamespace
            ? ""
            : $"namespace {typeSymbol.ContainingNamespace};";

        var name = typeSymbol.ToDisplayString(SymbolDisplayFormat.MinimallyQualifiedFormat);

        var global = "global::";
        var fullType = typeSymbol.ToDisplayString(SymbolDisplayFormat.FullyQualifiedFormat);
        if (fullType.StartsWith(global))
        {
            fullType = fullType.Substring(global.Length);
        }

        string typeString = "";
        if (typeSymbol.IsStatic)
        {
            typeString += "static ";
        }
        typeString += "partial ";
        if (typeSymbol.IsRecord)
        {
            typeString += "record ";
        }
        typeString += typeSymbol.IsValueType ? "struct" : "class";

        var code = $$"""
            #nullable enable
            using System;
            using System.Diagnostics;

            {{ns}}

            {{typeString}} {{name}}
            {
                private static class LocalDebug
                {
                    [Conditional("LOCAL_DEBUG")]
                    internal static void WriteLine(string s, [System.Runtime.CompilerServices.CallerMemberName] string memberName = "")
                    {
                        Debug.WriteLine($"{{name}}.{memberName}: {s}");
                    }
                }
            }
            """;

        context.AddSource(PathTools.ReplaceInvalidFileNameChars($"{fullType}.LocalDebug.g.cs"), code);
    }

}

﻿using Microsoft.CodeAnalysis;
