        /// サポート判定(メモリ版)
        /// </summary>
        /// <param name="filename">ファイル名(判定用)</param>
        /// <param name="buff">対象データ</param>
        /// <returns>サポートしていれば true</returns>
        public bool IsSupported(string filename, byte[] buff)
        {
