        #endregion


        #region 00AM 必須 GetArchiveInfo()
        private delegate int GetArchiveInfoFromFileDelegate([In] string filename, int offset, uint flag, out IntPtr hInfo);
        private delegate int GetArchiveInfoFromMemoryDelegate([In] byte[] buf, int offset, uint flag, out IntPtr hInfo);

        /// <summary>
        /// アーカイブ情報取得
        /// </summary>
        /// <param name="file">アーカイブファイル名</param>
        /// <returns>アーカイブエントリ情報(RAW)。失敗した場合は null</returns>
        public List<ArchiveFileInfoRaw>? GetArchiveInfo(string file)
        {
            if (hModule == IntPtr.Zero) throw new InvalidOperationException();
            var getArchiveInfo = GetApiDelegate<GetArchiveInfoFromFileDelegate>("GetArchiveInfo");

            IntPtr hInfo = IntPtr.Zero;
            try
            {
                int ret = getArchiveInfo(file, 0, 0, out hInfo);
                if (ret == 0)
                {
                    var list = new List<ArchiveFileInfoRaw>();
                    var structSize = Marshal.SizeOf<ArchiveFileInfoRaw>();
                    IntPtr p = NativeMethods.LocalLock(hInfo);
                    while (true)
                    {
                        ArchiveFileInfoRaw fileInfo = Marshal.PtrToStructure<ArchiveFileInfoRaw>(p);
                        if (string.IsNullOrEmpty(fileInfo.method)) break;
                        list.Add(fileInfo);
                        p += structSize;
                    }

                    return list;
                }
            }
            finally
            {
                NativeMethods.LocalUnlock(hInfo);
                NativeMethods.LocalFree(hInfo);
            }

            return null;
        }
        #endregion


        #region 00AM 必須 GetFile()
        private delegate int GetFileFromFileHandler(string filename, int position, out IntPtr hBuff, uint flag, ProgressCallback lpProgressCallback, int lData);
        private delegate int GetFileFromFileToFileHandler(string filename, int position, string dest, uint flag, ProgressCallback lpProgressCallback, int lData);

        /// <summary>
        /// アーカイブエントリ取得(メモリ版)
        /// </summary>
        /// <param name="file">アーカイブファイル名</param>
        /// <param name="position">アーカイブエントリ位置</param>
        /// <returns>出力されたバッファ。失敗した場合は null</returns>
        public byte[]? GetFile(string file, int position)
        {
            if (hModule == IntPtr.Zero) throw new InvalidOperationException();
            var getFile = GetApiDelegate<GetFileFromFileHandler>("GetFile");

            IntPtr hBuff = IntPtr.Zero;
            try
            {
                int ret = getFile(file, position, out hBuff, 0x0100, ProgressCallbackDummy, 0); // 0x0100 > File To Memory
                if (ret == 0)
                {
                    IntPtr pBuff = NativeMethods.LocalLock(hBuff);
                    var buffSize = (int)NativeMethods.LocalSize(hBuff);
                    if (buffSize == 0) throw new SusieException("Memory error.");
                    byte[] buf = new byte[buffSize];
                    Marshal.Copy(pBuff, buf, (int)0, (int)buffSize);
                    return buf;
                }
                return null;
            }
            finally
            {
                NativeMethods.LocalUnlock(hBuff);
                NativeMethods.LocalFree(hBuff);
            }
        }

        /// <summary>
        /// アーカイブエントリ取得(ファイル版)
        /// </summary>
        /// <param name="file">アーカイブファイル名</param>
        /// <param name="position">アーカイブエントリ位置</param>
        /// <param name="extractFolder">出力フォルダー</param>
        /// <returns>成功した場合は0</returns>
        public int GetFile(string file, int position, string extractFolder)
        {
            if (hModule == IntPtr.Zero) throw new InvalidOperationException();
            var getFile = GetApiDelegate<GetFileFromFileToFileHandler>("GetFile");

            return getFile(file, position, extractFolder, 0x0000, ProgressCallbackDummy, 0); // 0x0000 > File To File
        }

        #endregion


        #region 00IN 必須 GetPicture()
        private delegate int GetPictureFromMemoryDelegate([In] byte[] buf, int len, uint flag, out IntPtr pHBInfo, out IntPtr pHBm, ProgressCallback lpProgressCallback, int lData);
        private delegate int GetPictureFromFileDelegate([In] string filename, int offset, uint flag, out IntPtr pHBInfo, out IntPtr pHBm, ProgressCallback lpProgressCallback, int lData);



        /// <summary>
        /// 画像取得(メモリ版)
        /// </summary>
        /// <param name="buff">入力画像データ</param>
        /// <returns>Bitmap。失敗した場合は null</returns>
        public byte[]? GetPicture(byte[] buff)
        {
            if (hModule == IntPtr.Zero) throw new InvalidOperationException();
            var getPicture = GetApiDelegate<GetPictureFromMemoryDelegate>("GetPicture");

            IntPtr pHBInfo = IntPtr.Zero;
            IntPtr pHBm = IntPtr.Zero;
            try
            {
                int ret = getPicture(buff, buff.Length, 0x01, out pHBInfo, out pHBm, ProgressCallbackDummy, 0);
                if (ret == 0)
                {
                    IntPtr pBInfo = NativeMethods.LocalLock(pHBInfo);
                    int pBInfoSize = (int)NativeMethods.LocalSize(pHBInfo);
                    IntPtr pBm = NativeMethods.LocalLock(pHBm);
                    int pBmSize = (int)NativeMethods.LocalSize(pHBm);
                    return CreateBitmapImage(pBInfo, pBInfoSize, pBm, pBmSize);
                }
                return null;
            }
            finally
            {
                NativeMethods.LocalUnlock(pHBInfo);
                NativeMethods.LocalUnlock(pHBm);
                NativeMethods.LocalFree(pHBInfo);
                NativeMethods.LocalFree(pHBm);
            }
        }


        /// <summary>
        /// 画像取得(ファイル版)
        /// </summary>
        /// <param name="filename">入力ファイル名</param>
        /// <returns>Bitmap。失敗した場合は null</returns>
        public byte[]? GetPicture(string filename)
        {
            if (hModule == IntPtr.Zero) throw new InvalidOperationException();
            var getPicture = GetApiDelegate<GetPictureFromFileDelegate>("GetPicture");

            IntPtr pHBInfo = IntPtr.Zero;
            IntPtr pHBm = IntPtr.Zero;
            try
            {
                int ret = getPicture(filename, 0, 0x00, out pHBInfo, out pHBm, ProgressCallbackDummy, 0);
                if (ret == 0)
                {
                    IntPtr pBInfo = NativeMethods.LocalLock(pHBInfo);
                    int pBInfoSize = (int)NativeMethods.LocalSize(pHBInfo);
                    IntPtr pBm = NativeMethods.LocalLock(pHBm);
                    int pBmSize = (int)NativeMethods.LocalSize(pHBm);
                    return CreateBitmapImage(pBInfo, pBInfoSize, pBm, pBmSize);
                }
                return null;
            }
            finally
            {
                NativeMethods.LocalUnlock(pHBInfo);
                NativeMethods.LocalUnlock(pHBm);
                NativeMethods.LocalFree(pHBInfo);
                NativeMethods.LocalFree(pHBm);
            }
        }


        // Bitmap 作成
        private static byte[] CreateBitmapImage(IntPtr pBInfo, int pBInfoSize, IntPtr pBm, int pBmSize)
        {
            if (pBInfoSize == 0 || pBmSize == 0)
            {
                throw new SusieException("Memory error.");
            }

            var bf = CreateBitmapFileHeader(pBInfoSize, pBmSize);
            byte[] mem = new byte[bf.bfSize];
            GCHandle gch = GCHandle.Alloc(mem, GCHandleType.Pinned);
            try { Marshal.StructureToPtr<BitmapFileHeader>(bf, gch.AddrOfPinnedObject(), false); }
            finally { gch.Free(); }
            Marshal.Copy(pBInfo, mem, Marshal.SizeOf(bf), pBInfoSize);
            Marshal.Copy(pBm, mem, (int)bf.bfOffBits, pBmSize);
            return mem;
        }


        // BitmapFileHeader作成
        private static BitmapFileHeader CreateBitmapFileHeader(int pBInfoSize, int pBmSize)
        {
            var bf = new BitmapFileHeader();
            bf.bfSize += bf.bfOffBits;
            bf.bfType = 0x4d42;
            bf.bfSize = (uint)Marshal.SizeOf(bf) + (uint)pBInfoSize + (uint)pBmSize;
            bf.bfReserved1 = 0;
            bf.bfReserved2 = 0;
            bf.bfOffBits = (uint)Marshal.SizeOf(bf) + (uint)pBInfoSize;
            return bf;
        }
        #endregion
    }


    /// <summary>
    /// アーカイブエントリ情報(Raw)
    /// </summary>
    [StructLayout(LayoutKind.Sequential, Pack = 1, CharSet = CharSet.Ansi)]
    public struct ArchiveFileInfoRaw
    {
        [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 8)]
        public string method; // 圧縮法の種類
        public uint position; // ファイル上での位置
        public uint compsize; // 圧縮されたサイズ
        public uint filesize; // 元のファイルサイズ
        public uint timestamp; // ファイルの更新日時
        [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 200)]
        public string path; // 相対パス
        [MarshalAs(UnmanagedType.ByValTStr, SizeConst = 200)]
        public string filename; // ファイルネーム
        public uint crc; // CRC 
    }

}

﻿using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO;
using System.Linq;

namespace NeeView.Susie.Server
{
    public class SusiePluginCollection : IDisposable
    {
        public SusiePluginCollection()
        {
        }


        public string? PluginFolder { get; private set; }

        /// <summary>
        /// 書庫プラグインリスト
        /// </summary>
        public List<SusiePlugin> AMPluginList { get; private set; } = new List<SusiePlugin>();

        /// <summary>
        /// 画像プラグインリスト
        /// </summary>
        public List<SusiePlugin> INPluginList { get; private set; } = new List<SusiePlugin>();

        // すべてのプラグインのEnumerator
        public IEnumerable<SusiePlugin> PluginCollection
        {
            get
            {
                foreach (var plugin in AMPluginList) yield return plugin;
                foreach (var plugin in INPluginList) yield return plugin;
            }
        }


        #region IDisposable Support
        private bool _disposedValue = false;

        protected virtual void Dispose(bool disposing)
        {
            if (!_disposedValue)
            {
                if (disposing)
                {
                    foreach (var plugin in PluginCollection)
                    {
                        plugin.Dispose();
                    }
                    INPluginList.Clear();
                    AMPluginList.Clear();
                }

                _disposedValue = true;
            }
        }

        public void Dispose()
        {
            Dispose(true);
            GC.SuppressFinalize(this);
        }
        #endregion

        public void Initialize(string spiFolder, List<SusiePluginInfo> settings)
        {
            if (string.IsNullOrWhiteSpace(spiFolder)) throw new ArgumentException("spiFolder must be not null.", nameof(spiFolder));
            if (!Directory.Exists(spiFolder)) throw new DirectoryNotFoundException($"Directory not found: {spiFolder}");

            PluginFolder = spiFolder;

            var spiFiles = Directory.GetFiles(spiFolder, "*.spi");

            var plugins = new List<SusiePlugin>();
            foreach (var fileName in spiFiles)
            {
                var name = Path.GetFileName(fileName);
                var setting = settings.FirstOrDefault(e => e.Name == name);
                var spi = SusiePlugin.Create(fileName, setting);
                if (spi != null)
                {
                    if (spi.PluginType == SusiePluginType.None)
                    {
                        Trace.WriteLine("SusiePluginCollection.Initialize: no support SPI (wrong API version): " + Path.GetFileName(fileName));
                        spi.Dispose();
                    }
                    else
                    {
                        plugins.Add(spi);
                    }
                }
                else
                {
                    Trace.WriteLine("SusiePluginCollection.Initialize: no support SPI (Exception): " + Path.GetFileName(fileName));
                }
            }

            INPluginList = new List<SusiePlugin>(plugins.Where(e => e.PluginType == SusiePluginType.Image));
            AMPluginList = new List<SusiePlugin>(plugins.Where(e => e.PluginType == SusiePluginType.Archive));
        }


        public void SetPluginSetting(List<SusiePluginInfo> settings)
        {
            if (settings == null) return;

            foreach (var plugin in PluginCollection)
            {
                var setting = settings.FirstOrDefault(e => e.Name == plugin.Name);
                if (setting != null)
                {
                    plugin.Restore(setting);
                }
            }
        }

        public void SortPlugins(List<string> orders)
        {
            if (orders == null) return;

            var comparer = new PluginOrderComparer(orders);
            INPluginList = new List<SusiePlugin>(INPluginList.OrderBy(e => e, comparer));
            AMPluginList = new List<SusiePlugin>(AMPluginList.OrderBy(e => e, comparer));
        }


        /// <summary>
        /// 予約順にSPIを並び替えるためのコンペア 
        /// </summary>
        class PluginOrderComparer : IComparer<SusiePlugin>
        {
            private readonly List<string> _order;

            public PluginOrderComparer(List<string> order)
            {
                _order = order;
            }

            public int Compare(SusiePlugin? spiX, SusiePlugin? spiY)
            {
                if (spiX is null) return (spiY is null) ? 0 : -1;
                if (spiY is null) return 1;

                int indexX = _order.IndexOf(spiX.Name);
                int indexY = _order.IndexOf(spiY.Name);
                return indexX - indexY;
            }
        }


        // 名前でプラグイン取得
        public SusiePlugin? GetPluginFromName(string name)
        {
            return PluginCollection.FirstOrDefault(e => e.Name == name);
        }

        // 対応アーカイブプラグイン取得
        public SusiePlugin? GetArchivePlugin(string fileName, byte[] buff, bool isCheckExtension, string? pluginName)
        {
            return GetPlugin(AMPluginList, fileName, buff, isCheckExtension, pluginName);
        }


        // 対応画像プラグイン取得
        public SusiePlugin? GetImagePlugin(string fileName, byte[] buff, bool isCheckExtension)
        {
            return GetPlugin(INPluginList, fileName, buff, isCheckExtension, null);
        }

        /// <summary>
        /// 対応プラグインを取得
        /// </summary>
        public SusiePlugin? GetPlugin(List<SusiePlugin> plugins, string fileName, byte[] buff, bool isCheckExtension, string? pluginName)
        {
            plugins = plugins ?? PluginCollection.ToList();
            buff = buff ?? SusiePlugin.LoadHead(fileName);

            // プラグイン指定
            if (pluginName != null)
            {
                var plugin = plugins.FirstOrDefault(e => e.Name == pluginName);
                if (plugin is not null) return plugin;
            }

            foreach (var plugin in plugins)
            {
                try
                {
                    if (plugin.IsSupported(fileName, buff, isCheckExtension))
                    {
                        return plugin;
                    }
                }
                catch (Exception ex)
                {
                    Trace.WriteLine($"SusiePluginCollection.GetPlugin: Exception: {ex.Message}");
                }
            }
            return null;
        }



        /// <summary>
        /// 画像取得
        /// </summary>
        /// <param name="plugins">仕様プラグイン。nullですべてのプラグインから取得を試みる</param>
        /// <param name="fileName">ファイル名</param>
        /// <param name="buff">ファイル実体。指定されていればこのメモリから画像生成する</param>
        /// <param name="isCheckExtension">拡張子判定を行う？</param>
        public SusieImage? GetImage(List<SusiePlugin> plugins, string fileName, byte[]? buff, bool isCheckExtension)
        {
            plugins = plugins ?? INPluginList;

            var fromFile = buff is null;
            buff = buff ?? SusiePlugin.LoadHead(fileName);

            foreach (var plugin in plugins.Where(e => e.IsEnabled))
            {
                try
                {
                    var bitmapImage = fromFile
                        ? plugin.GetPictureFromFile(fileName, buff, isCheckExtension)
                        : plugin.GetPicture(fileName, buff, isCheckExtension);
                    if (bitmapImage != null)
                    {
                        return new SusieImage(plugin.ToSusiePluginInfo(), bitmapImage);
                    }
                }
                catch (Exception ex)
                {
                    Trace.WriteLine($"SusiePluginCollection.GetImage: Exception: {ex.Message}");
                }
            }

            return null;
        }
    }
}

﻿using NeeLaboratory;
using NeeLaboratory.Remote;
using System;
using System.Collections.Generic;
using System.Diagnostics;


namespace NeeView.Susie.Server
{
    public class SusiePluginRemoteServer
    {
        private readonly SimpleServer _server;
        private readonly SusiePluginServer _process;


        public SusiePluginRemoteServer()
        {
            var name = SusiePluginRemote.CreateServerName(Process.GetCurrentProcess());
            Trace.WriteLine($"ServerName: {name}");
            _server = new SimpleServer(name);
            _server.AddReceiver(SusiePluginCommandId.Initialize, Initialize);
            _server.AddReceiver(SusiePluginCommandId.GetPlugin, GetPlugin);
            _server.AddReceiver(SusiePluginCommandId.SetPlugin, SetPlugin);
            _server.AddReceiver(SusiePluginCommandId.SetPluginOrder, SetPluginOrder);
            _server.AddReceiver(SusiePluginCommandId.ShowConfigurationDlg, ShowConfigurationDlg);
            _server.AddReceiver(SusiePluginCommandId.GetArchivePlugin, GetArchivePlugin);
            _server.AddReceiver(SusiePluginCommandId.GetImagePlugin, GetImagePlugin);
            _server.AddReceiver(SusiePluginCommandId.GetImage, GetImage);
            _server.AddReceiver(SusiePluginCommandId.GetArchiveEntries, GetArchiveEntries);
            _server.AddReceiver(SusiePluginCommandId.ExtractArchiveEntry, ExtractArchiveEntry);
            _server.AddReceiver(SusiePluginCommandId.ExtractArchiveEntryToFolder, ExtractArchiveEntryToFolder);


            _process = new SusiePluginServer();
        }

        public void Run()
        {
            _server.ServerProcess();
        }

        private static TResult DeserializeChunk<TResult>(Chunk chunk)
            where TResult : class
        {
            if (chunk.Data is null) throw new InvalidOperationException("chunk.Data must not be null");

            return SusieCommandSerializer.Deserialize<TResult>(chunk.Data);
        }

        private static List<Chunk> CreateResult<T>(int id, T result)
        {
            var chunk = new Chunk(id, SusieCommandSerializer.Serialize(result));
            return new List<Chunk>() { chunk };
        }

        private static List<Chunk> CreateResultIsSuccess(int id, bool isSuccess)
        {
            var chunk = new Chunk(id, SusieCommandSerializer.Serialize(new SusiePluginCommandResult(isSuccess)));
            return new List<Chunk>() { chunk };
        }


        private List<Chunk> Initialize(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandInitialize>(command[0]);
            Trace.WriteLine($"Remote.Initialize: {args.PluginFolder}, {args.Plugins}");
            _process.Initialize(args.PluginFolder, args.Plugins);
            return CreateResultIsSuccess(SusiePluginCommandId.Initialize, true);
        }

        private List<Chunk> GetPlugin(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandGetPlugin>(command[0]);
            Trace.WriteLine($"Remote.GetPlugin: {args.PluginNames}");
            var pluginInfoList = _process.GetPlugin(args.PluginNames);
            return CreateResult(SusiePluginCommandId.GetPlugin, new SusiePluginCommandGetPluginResult(pluginInfoList));
        }

        private List<Chunk> SetPlugin(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandSetPlugin>(command[0]);
            Trace.WriteLine($"Remote.SetPlugin: {args.Plugins}");
            _process.SetPlugin(args.Plugins);
            return CreateResultIsSuccess(SusiePluginCommandId.SetPlugin, true);
        }

        private List<Chunk> SetPluginOrder(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandSetPluginOrder>(command[0]);
            Trace.WriteLine($"Remote.SetPluginOrder: {args.Order}");
            _process.SetPluginOrder(args.Order);
            return CreateResultIsSuccess(SusiePluginCommandId.SetPluginOrder, true);
        }

        private List<Chunk> ShowConfigurationDlg(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandShowConfigurationDlg>(command[0]);
            Trace.WriteLine($"Remote.ShowConfigurationDlg: {args.PluginName}");
            _process.ShowConfigurationDlg(args.PluginName, args.HWnd);
            return CreateResultIsSuccess(SusiePluginCommandId.ShowConfigurationDlg, true);
        }


        private List<Chunk> GetArchivePlugin(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandGetArchivePlugin>(command[0]);
            Trace.WriteLine($"Remote.GetArchivePlugin: {args.FileName}");
            var buff = command[1].Data;
            var pluginInfo = _process.GetArchivePlugin(args.FileName, buff, args.IsCheckExtension, args.PluginName);
            return CreateResult(SusiePluginCommandId.GetArchivePlugin, new SusiePluginCommandGetArchivePluginResult(pluginInfo));
        }

        private List<Chunk> GetImagePlugin(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandGetImagePlugin>(command[0]);
            Trace.WriteLine($"Remote.GetImagePlugin: {args.FileName}");
            var buff = command[1].Data;
            var pluginInfo = _process.GetImagePlugin(args.FileName, buff, args.IsCheckExtension);
            return CreateResult(SusiePluginCommandId.GetImagePlugin, new SusiePluginCommandGetImagePluginResult(pluginInfo));
        }

        private List<Chunk> GetImage(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandGetImage>(command[0]);
            Trace.WriteLine($"Remote.GetImage: {args.FileName}");
            var buff = command[1].Data;
            var susieImage = _process.GetImage(args.PluginName, args.FileName, buff, args.IsCheckExtension);
            if (susieImage != null)
            {
                var result = CreateResult(SusiePluginCommandId.GetImage, new SusiePluginCommandGetImageResult(susieImage.Plugin));
                result.Add(new Chunk(SusiePluginCommandId.GetImage, susieImage.BitmapData));
                return result;
            }
            else
            {
                var result = CreateResult(SusiePluginCommandId.GetImage, new SusiePluginCommandGetImageResult(null));
                result.Add(new Chunk(SusiePluginCommandId.GetImage, null));
                return result;
            }
        }


        private List<Chunk> GetArchiveEntries(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandGetArchiveEntries>(command[0]);
            Trace.WriteLine($"Remote.GetArchiveEntries: {args.FileName}");
            var entries = _process.GetArchiveEntries(args.PluginName, args.FileName);
            return CreateResult(SusiePluginCommandId.GetArchiveEntries, new SusiePluginCommandGetArchiveEntriesResult(entries));
        }

        private List<Chunk> ExtractArchiveEntry(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandExtractArchiveEntry>(command[0]);
            Trace.WriteLine($"Remote.ExtractArchiveEntry: {args.FileName}, {args.Position}");
            var buff = _process.ExtractArchiveEntry(args.PluginName, args.FileName, args.Position);
            return new List<Chunk>() { new Chunk(SusiePluginCommandId.ExtractArchiveEntry, buff) };
        }

        private List<Chunk> ExtractArchiveEntryToFolder(List<Chunk> command)
        {
            var args = DeserializeChunk<SusiePluginCommandExtractArchiveEntryToFolder>(command[0]);
            Trace.WriteLine($"Remote.ExtractArchiveEntryToFolder: {args.FileName}, {args.Position}, {args.ExtractFolder}");
            _process.ExtractArchiveEntryToFolder(args.PluginName, args.FileName, args.Position, args.ExtractFolder);
            return CreateResultIsSuccess(SusiePluginCommandId.ExtractArchiveEntryToFolder, true);
        }
    }
}

﻿using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

namespace NeeView.Susie.Server
{
    public class SusiePluginServer : IRemoteSusiePlugin, IDisposable
    {
        private SusiePluginCollection _pluginCollection = new();

        public SusiePluginServer()
        {

        }

        #region IDisposable Support
        private bool _disposedValue = false;

        protected virtual void Dispose(bool disposing)
        {
            if (!_disposedValue)
            {
                if (disposing)
                {
                    _pluginCollection?.Dispose();
                }
                _disposedValue = true;
            }
        }

        public void Dispose()
        {
            Dispose(true);
            GC.SuppressFinalize(this);
        }
        #endregion


        public void Initialize(string pluginFolder, List<SusiePluginInfo> plugins)
        {
            _pluginCollection?.Dispose();

            _pluginCollection = new SusiePluginCollection();

            _pluginCollection.Initialize(pluginFolder, plugins);
            _pluginCollection.SortPlugins(plugins.Select(e => e.Name).ToList());
        }


        public void ExtractArchiveEntryToFolder(string pluginName, string fileName, int position, string extractFolder)
        {
            var plugin = _pluginCollection.AMPluginList.FirstOrDefault(e => e.Name == pluginName);
            if (plugin == null) throw new SusieException($"Cannot found plugin", pluginName);

            plugin.ExtractArchiveEntryToFolder(fileName, position, extractFolder);
        }

        public List<SusieArchiveEntry> GetArchiveEntries(string pluginName, string fileName)
        {
            var plugin = _pluginCollection.AMPluginList.FirstOrDefault(e => e.Name == pluginName);
            if (plugin == null) throw new SusieException($"Cannot found plugin", pluginName);

            var collection = plugin.GetArchiveEntryCollection(fileName);
            return collection.Select(e => e.ToSusieArchiveEntry()).ToList();
        }

        public SusiePluginInfo? GetArchivePlugin(string fileName, byte[]? buff, bool isCheckExtension, string? pluginName)
        {
            // buff==nullのときの処理。ヘッダ2KBを読み込む
            if (buff == null)
            {
                buff = new byte[4096];
                using (var fs = new FileStream(fileName, FileMode.Open, FileAccess.Read))
                {
                    _ = fs.Read(buff, 0, 2048);
                }
            }

            var plugin = _pluginCollection.GetArchivePlugin(fileName, buff, isCheckExtension, pluginName);
            if (plugin is null) return null;

            return plugin.ToSusiePluginInfo();
        }

        public SusiePluginInfo? GetImagePlugin(string fileName, byte[]? buff, bool isCheckExtension)
        {
            // buff==nullのときの処理。ヘッダ2KBを読み込む
            if (buff == null)
            {
                buff = new byte[4096];
                using (var fs = new FileStream(fileName, FileMode.Open, FileAccess.Read))
                {
                    _ = fs.Read(buff, 0, 2048);
                }
            }

            var plugin = _pluginCollection.GetImagePlugin(fileName, buff, isCheckExtension);
            if (plugin is null) return null;

            return plugin.ToSusiePluginInfo();
        }

        public SusieImage? GetImage(string? pluginName, string fileName, byte[]? buff, bool isCheckExtension)
        {
            var plugins = _pluginCollection.INPluginList;
            if (pluginName != null)
            {
                var plugin = _pluginCollection.INPluginList.FirstOrDefault(e => e.Name == pluginName);
                if (plugin == null) throw new SusieException($"Cannot found plugin", pluginName);

                plugins = new List<Server.SusiePlugin>() { plugin };
            }

            var image = _pluginCollection.GetImage(plugins, fileName, buff, isCheckExtension);
            if (image is null) return null;

            return image;
        }

        public List<SusiePluginInfo> GetPlugin(List<string>? pluginNames)
        {
            var plugins = pluginNames != null
                ? pluginNames.Select(e => _pluginCollection.GetPluginFromName(e)).WhereNotNull()
                : _pluginCollection.PluginCollection;

            return plugins.Select(e => e.ToSusiePluginInfo()).ToList();
        }

        public byte[] ExtractArchiveEntry(string pluginName, string fileName, int position)
        {
            var plugin = _pluginCollection.AMPluginList.FirstOrDefault(e => e.Name == pluginName);
            if (plugin == null) throw new SusieException("Cannot found plugin", pluginName);

            return plugin.LoadArchiveEntry(fileName, position);
        }

        public void SetPlugin(List<SusiePluginInfo> plugins)
        {
            if (plugins == null || !plugins.Any()) return;
            _pluginCollection.SetPluginSetting(plugins);
        }

        public void SetPluginOrder(List<string> order)
        {
            if (order == null || !order.Any()) return;
            _pluginCollection.SortPlugins(order);
        }


        public void ShowConfigurationDlg(string pluginName, int hwnd)
        {
            var plugin = _pluginCollection.GetPluginFromName(pluginName);
            if (plugin is null) return;

            plugin.OpenConfigurationDialog(new IntPtr(hwnd));
        }
    }
}

