            var node2a = tree.Add(@"C:\DirA\DirB\1A\2A");
            var node2b = tree.Add(@"C:\DirA\DirB\1A\2B");
            var node3c = tree.Add(@"C:\DirA\DirB\3A\3B\3C");

            var node9x = tree.Add(@"C:\DirA\Dir9B\3A\3B\3C");
            Assert.Null(node9x);

            // add empty exception
            Assert.Throws<ArgumentException>(() => tree.Add(""));

            // add same
