﻿using System;
using System.Diagnostics;
using System.IO;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;
using System.Windows;
using System.Windows.Threading;

namespace NeeView
{
    public partial class App
    {
        public static string ErrorLogFileName => System.IO.Path.Combine(Environment.LocalApplicationDataPath, $"ErrorLog-{DateTime.Now.ToString("yyyyMMddTHHmmss")}.txt");


        // 未処理例外発生数
        private int _exceptionCount = 0;


        public event EventHandler? CriticalError;


        /// <summary>
        /// 全ての未処理例外をキャッチするハンドル登録
        /// </summary>
        private void InitializeUnhandledException()
        {
#if DEBUG
            TaskScheduler.UnobservedTaskException += TaskScheduler_UnobservedTaskException;
#endif
            AppDomain.CurrentDomain.UnhandledException += CurrentDomain_UnhandledException;
            this.DispatcherUnhandledException += Application_DispatcherUnhandledException;
        }

        private void TerminateUnhandledException()
        {
#if DEBUG
            TaskScheduler.UnobservedTaskException -= TaskScheduler_UnobservedTaskException;
#endif
            AppDomain.CurrentDomain.UnhandledException -= CurrentDomain_UnhandledException;
            this.DispatcherUnhandledException -= Application_DispatcherUnhandledException;
        }

        /// <summary>
        /// TaskScheduler の未処理例外処理
        /// </summary>
        private static void TaskScheduler_UnobservedTaskException(object? sender, UnobservedTaskExceptionEventArgs e)
        {
            // OperationCanceledException は正常とする
            if (IsOperationCanceledException(e.Exception))
            {
                e.SetObserved();
            }
            else
            {
                // NOTE: .NET6 では ThrowUnobservedTaskExceptions が機能しないためここで例外を発行してアプリ終了させる
                throw e.Exception;
            }
        }

        /// <summary>
        /// Dispatcher の未処理例外処理
        /// </summary>
        private static void Application_DispatcherUnhandledException(object sender, DispatcherUnhandledExceptionEventArgs e)
        {
            // OperationCanceledException は正常とする
            if (IsOperationCanceledException(e.Exception))
            {
                e.Handled = true;
            }
        }

        /// <summary>
        /// 例外がOperationCanceledExceptionのみであるか
        /// </summary>
        private static bool IsOperationCanceledException(Exception exception)
        {
            if (exception is AggregateException aggregateException)
            {
                return aggregateException.InnerExceptions.All(x => x is OperationCanceledException);
            }
            else if (exception is OperationCanceledException)
            {
                return true;
            }

            return false;
        }

        /// <summary>
        /// アプリドメインの未処理例外の処理。アプリは継続不能
        /// </summary>
        private void CurrentDomain_UnhandledException(object? sender, UnhandledExceptionEventArgs e)
        {
            int count = Interlocked.Increment(ref _exceptionCount);
            if (count >= 2) return;

            CriticalError?.Invoke(this, EventArgs.Empty);

            if (e.ExceptionObject is not Exception exception) return;

            string errorLog = CreateErrorLog(exception);

            // エラーログファイルに出力
            string errorLogFileName = ErrorLogFileName;
            ExportErrorLog(errorLogFileName, errorLog);

            // エラーダイアログ表示
            ShowErrorLogDialog(errorLog, errorLogFileName);

            Debug.WriteLine("UnhandledException callback done.");
        }

        /// <summary>
        /// エラーログテキスト作成
        /// </summary>
        /// <param name="exception">例外</param>
        public static string CreateErrorLog(Exception exception)
        {
            string errorLog;
            using (var writer = new StringWriter())
            {
                writer.WriteLine(Environment.VersionNote);
                writer.WriteLine("");
                writer.WriteLine(exception.ToStackString());

                errorLog = writer.ToString();
            }

            return errorLog;
        }

        /// <summary>
        /// エラーログファイルに出力
        /// </summary>
        /// <param name="errorLog"></param>
        /// <returns>エラーログファイル名</returns>
        public static void ExportErrorLog(string errorLogFileName, string errorLog)
        {
            using (var writer = new StreamWriter(new FileStream(errorLogFileName, FileMode.Create, FileAccess.Write)))
            {
                writer.Write(errorLog);
            }
        }

        /// <summary>
        /// エラーログファイルに出力
        /// </summary>
        /// <param name="exception"></param>
        /// <returns></returns>
        public static void ExportErrorLog(string errorLogFileName, Exception exception)
        {
            ExportErrorLog(errorLogFileName, CreateErrorLog(exception));
        }

        /// <summary>
        /// エラーダイアログ表示
        /// </summary>
        private static void ShowErrorLogDialog(string errorLog, string errorLogFileName)
        {
            try
            {
                AppDispatcher.Invoke(() =>
                {
                    var dialog = new CriticalErrorDialog(errorLog, errorLogFileName);
                    dialog.ShowInTaskbar = true;
                    dialog.Topmost = true;
                    dialog.ShowDialog();
                });
            }
            catch
            {
                MessageBox.Show(errorLog, "Abort", MessageBoxButton.OK, MessageBoxImage.Hand);
            }
        }
    }
}

﻿using NeeLaboratory.Linq;
using NeeView.Data;
using NeeView.Properties;
using NeeView.Windows;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Windows;

namespace NeeView
{
    public enum SwitchOption
    {
        off,
        on,
    }

    public enum WindowStateOption
    {
        normal,
        min,
        max,
        full
    }

    public static class WindowStateOptionExtensions
    {
        public static WindowStateEx ToWindowStateEx(this WindowStateOption? option)
        {
            return option switch
            {
                WindowStateOption.normal => WindowStateEx.Normal,
                WindowStateOption.min => WindowStateEx.Minimized,
                WindowStateOption.max => WindowStateEx.Maximized,
                WindowStateOption.full => WindowStateEx.FullScreen,
                _ => WindowStateEx.None,
            };
        }

    }

    public class CommandLineOption
    {
        [OptionMember("h", "help", Default = "true", HelpText = "AppOption.IsHelp")]
        public bool IsHelp { get; set; }

        [OptionMember("v", "version", Default = "true", HelpText = "AppOption.IsVersion")]
        public bool IsVersion { get; set; }

        [OptionMember("x", "setting", HasParameter = true, RequireParameter = true, HelpText = "AppOption.SettingFilename")]
        public string? SettingFilename { get; set; }

        [OptionMember("b", "blank", Default = "on", HelpText = "AppOption.IsBlank")]
        public SwitchOption IsBlank { get; set; }

        [OptionMember("r", "reset-placement", Default = "on", HelpText = "AppOption.IsResetPlacement")]
        public SwitchOption IsResetPlacement { get; set; }

        [OptionMember("n", "new-window", Default = "on", HasParameter = true, HelpText = "AppOption.IsNewWindow")]
        public SwitchOption? IsNewWindow { get; set; }

        [OptionMember("s", "slideshow", Default = "on", HasParameter = true, HelpText = "AppOption.IsSlideShow")]
        public SwitchOption? IsSlideShow { get; set; }

        [OptionMember("o", "folderlist", HasParameter = true, RequireParameter = true, HelpText = "AppOption.FolderList")]
        public string? FolderList { get; set; }

        [OptionMember("l", "language", HasParameter = true, RequireParameter = true, HelpText = "AppOption.Language")]
        public string? Language { get; set; }

        [OptionMember(null, "window", HasParameter = true, RequireParameter = true, HelpText = "AppOption.WindowState")]
        public WindowStateOption? WindowState { get; set; }

        [OptionMember(null, "script", HasParameter = true, RequireParameter = true, HelpText = "AppOption.ScriptFile")]
        public string? ScriptFile { get; set; }

        [OptionMember(null, "clear-registry", Default = "true", HelpText = "AppOption.ClearRegistry")]
        public bool IsClearRegistry { get; set; }

#if DEBUG
        [OptionMember(null, "debug", HasParameter = true, RequireParameter = true, IsVisible = false)]
        public string? DebugCommand { get; set; }
#endif

        [OptionValues]
        public List<string> Values { get; set; } = new List<string>();


        public QueryPath? FolderListQuery { get; private set; }
        public QueryPath? ScriptQuery { get; private set; }


        public void Validate()
        {
            try
            {
                Values = Values.Select(e => Path.GetFullPath(e)).WhereNotNull().ToList();

                FolderListQuery = GetFullQueryPath(FolderList);
                ScriptQuery = GetFullQueryPath(ScriptFile);

                if (this.SettingFilename != null)
                {
                    if (!File.Exists(this.SettingFilename))
                    {
                        throw new ArgumentException($"{TextResources.GetString("OptionArgumentException.FileNotFound")}: {this.SettingFilename}");
                    }
                    this.SettingFilename = Path.GetFullPath(this.SettingFilename);
                }
                else
                {
                    this.SettingFilename = Path.Combine(Environment.LocalApplicationDataPath, SaveDataProfile.UserSettingFileName);
                }
            }
            catch (Exception ex)
            {
                new MessageDialog(ex.Message, TextResources.GetString("BootErrorDialog.Title")).ShowDialog();
                throw new OperationCanceledException("Wrong startup parameter");
            }
        }


        private QueryPath? GetFullQueryPath(string? src)
        {
            if (string.IsNullOrWhiteSpace(src)) return null;

            var query = new QueryPath(src);
            if (query.Path is null) return null;

            if (query.Scheme != QueryScheme.File)
            {
                return query;
            }

            return query with { Path = Path.GetFullPath(query.Path) };
        }
    }


    public partial class App
    {
        public static CommandLineOption ParseArguments(string[] args)
        {
            var optionMap = new OptionMap<CommandLineOption>();
            CommandLineOption option;

            try
            {
                var items = new List<string>(args);

                // プロトコル起動を吸収
                const string scheme = "neeview-open:";
                if (items.Any() && items[0].StartsWith(scheme, StringComparison.Ordinal))
                {
                    items[0] = items[0].Replace(scheme, "", StringComparison.Ordinal);
                    if (string.IsNullOrWhiteSpace(items[0]))
                    {
                        items.RemoveAt(0);
                    }
                }

                option = optionMap.ParseArguments(items.ToArray());
            }
            catch (Exception ex)
            {
                var dialog = new MessageDialog(ex.Message, TextResources.GetString("BootErrorDialog.Title"));
                dialog.SizeToContent = SizeToContent.WidthAndHeight;
                dialog.ContentRendered += (s, e) => dialog.InvalidateVisual();
                throw new OperationCanceledWithDialogException("Wrong startup parameter", dialog);
            }

            if (option.IsHelp)
            {
                var dialog = new MessageDialog(optionMap.GetCommandLineHelpText(), TextResources.GetString("BootOptionDialog.Title"));
                dialog.SizeToContent = SizeToContent.WidthAndHeight;
                dialog.ContentRendered += (s, e) => dialog.InvalidateVisual();
                throw new OperationCanceledWithDialogException("Show command line help", dialog);
            }

            if (option.IsClearRegistry)
            {
                Environment.ClearRegistry();
                throw new OperationCanceledException("Clear registries for shell");
            }

            return option;
        }
    }


    public class OperationCanceledWithDialogException : OperationCanceledException
    {
        public OperationCanceledWithDialogException(string? message, MessageDialog dialog) : base(message)
        {
            Dialog = dialog;
        }

        public OperationCanceledWithDialogException(string? message, MessageDialog dialog, Exception innerException) : base(message, innerException)
        {
            Dialog = dialog;
        }

        public MessageDialog Dialog { get; }

        public void ShowDialog()
        {
            Dialog.ShowDialog();
        }
    }
}

﻿using NeeView.Interop;
using NeeView.Native;
using NeeView.Properties;
using NeeView.Text.SimpleHtmlBuilder;
using NeeView.Windows;
using System;
using System.Diagnostics;
using System.Globalization;
using System.Runtime.CompilerServices;
using System.Threading.Tasks;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Input;

namespace NeeView
{
    /// <summary>
    /// App.xaml の相互作用ロジック
    /// </summary>
    public partial class App : Application
    {
        private static App? _current;
        public static new App Current => _current ?? throw new InvalidOperationException("_current must not be null");


        private bool _isSplashScreenVisible;
        private bool _isTerminated;
        private readonly int _tickBase = System.Environment.TickCount;
        private CommandLineOption? _option;
        private MultiBootService? _multiBootService;


        // オプション設定
        public CommandLineOption Option => _option ?? throw new InvalidOperationException("_option must not be null");

        // システムロック
        public System.Threading.Lock Lock { get; } = new();

        // 起動日時
        public DateTime StartTime { get; private set; }

        // 開発用：ストップウォッチ
        public Stopwatch Stopwatch { get; private set; } = new();

        // MainWindowはLoad完了している？
        public bool IsMainWindowLoaded { get; set; }

        /// <summary>
        /// アプリの起動時間(ms)取得
        /// </summary>
        public int TickCount => System.Environment.TickCount - _tickBase;


        /// <summary>
        /// Startup
        /// </summary>
        private async void Application_Startup(object sender, StartupEventArgs e)
        {
            _current = this;

            StartTime = DateTime.Now;
            Stopwatch.Start();

            // DLL 検索パスから現在の作業ディレクトリ (CWD) を削除
            NativeMethods.SetDllDirectory("");

#if TRACE_LOG
            var nowTime = DateTime.Now;
            var traceLogFilename = $"Trace{nowTime.ToString("yyMMdHHmmss")}.log";
            StreamWriter sw = new StreamWriter(traceLogFilename) { AutoFlush = true };
            TextWriterTraceListener twtl = new TextWriterTraceListener(TextWriter.Synchronized(sw), "MyListener");
            Trace.Listeners.Add(twtl);
            Trace.WriteLine($"Trace: Start ({nowTime})");
#endif

            // 起動処理排他ロック取得。時間内 (30sec) に獲得できなければアプリ終了
            var bootLock = new BootProcessLock(30 * 1000);
            var bootLockKey = bootLock.Lock();

            this.ShutdownMode = ShutdownMode.OnExplicitShutdown;

            try
            {
                // [開発用] ログ出力設定
                if (!string.IsNullOrEmpty(Environment.LogFile))
                {
                    var twtl = new TextWriterTraceListener(Environment.LogFile, "TraceLog");
                    Trace.Listeners.Add(twtl);
                    Trace.AutoFlush = true;
                    Trace.WriteLine(System.Environment.NewLine + new string('=', 80));
                }

                Trace.WriteLine($"App.Startup: PID={System.Environment.ProcessId}: {DateTime.Now}");

                // 未処理例外ハンドル
                InitializeUnhandledException();

                await InitializeAsync(e);
            }
            catch (OperationCanceledException ex)
            {
                Trace.WriteLine("InitializeCancelException: " + ex.Message);
                bootLockKey.Dispose();

                if (ex is OperationCanceledWithDialogException dialogException)
                {
                    dialogException.ShowDialog();
                }

                ShutdownWithoutSave();
                return;
            }
            finally
            {
                bootLockKey.Dispose();
                bootLock.Dispose();
            }

            Trace.WriteLine($"App.Initialized: {Stopwatch.ElapsedMilliseconds}ms");

            // ToolTipService default properties
            ToolTipService.BetweenShowDelayProperty.OverrideMetadata(typeof(DependencyObject), new FrameworkPropertyMetadata(0));

            this.ShutdownMode = ShutdownMode.OnMainWindowClose;

            // メインウィンドウ起動
            var mainWindow = new MainWindow();
            WindowParameters.Initialize(mainWindow);

            NVInterop.NVFpReset();
            mainWindow.Show();

            MessageDialog.IsShowInTaskBar = false;
        }

        /// <summary> 
        /// 初期化 
        /// </summary>
        private async ValueTask InitializeAsync(StartupEventArgs e)
        {
            Debug.WriteLine($"App.InitializeAsync...: {Stopwatch.ElapsedMilliseconds}ms");

            this.ShutdownMode = ShutdownMode.OnExplicitShutdown;

            // AnimatedImage ライブラリ初期化
            AnimatedImageChecker.InitializeLibrary();

            // APPXデータフォルダ移動 (ver.38)
            Environment.CorrectLocalAppDataFolder();

            // コマンドライン引数処理
            _option = ParseCommandLineOption(e.Args);

            // カレントディレクトリを実行ファイルの場所に変更。ファイルロック回避のため
            System.IO.Directory.SetCurrentDirectory(Environment.AssemblyFolder);

            // 多重起動サービス起動
            _multiBootService = new MultiBootService();

            // セカンドプロセス判定
            Environment.IsSecondProcess = _multiBootService.IsServerExists;

            DebugStamp("UserSettingLoading...");

            // load UserSetting bytes
            UserSetting? setting = null;
            var settingResource = new UserSettingResource(_option.SettingFilename);

            // create boot setting
            var boot = settingResource.LoadBootSetting();
            if (boot is null)
            {
                setting = CreateUserSetting(settingResource);
                Debug.Assert(setting.Config is not null);
                boot = BootSetting.Create(setting.Config);
            }

            // If multiple launches are not possible, send parameters to the main app to terminate.
            if (!CanStart(boot.IsMultiBootEnabled))
            {
                await _multiBootService.RemoteLoadAsAsync(Option.Values);
                throw new OperationCanceledException("Already started.");
            }

            // show splash screen
            ShowSplashScreen(boot);

            // initialize before UserSetting
            var language = _option.Language ?? boot.Language;
            InitializeTextResource(language);
            InitializeHtmlNode();
            InitializeCommandTable();

            // ensure UserSetting
            setting ??= CreateUserSetting(settingResource);
            SaveData.Current.SetUserSettingFileStamp(setting.FileStamp);
            UserSettingTools.Restore(setting, replaceConfig: true);

            // fix language
            if (_option.Language is null)
            {
                Config.Current.System.Language = TextResources.Culture.Name;
            }

            DebugStamp("UserSettingLoaded");

            // show version dialog
            if (this.Option.IsVersion)
            {
                ShowVersionDialog();
                throw new OperationCanceledException("Displayed version dialog.");
            }

            // initialize after UserSetting
            InitializeSupportFileType(Config.Current);
            InitializeTemporary(Config.Current);
            InitializeImeKey(Config.Current);
            InitializeTheme();
        }

        /// <summary>
        /// コマンドライン引数処理
        /// </summary>
        /// <returns></returns>
        private CommandLineOption ParseCommandLineOption(string[] args)
        {
            // コマンドライン引数処理
            var option = ParseArguments(args);
            option.Validate();

            // シフトキー起動は新しいウィンドウで
            if (Keyboard.IsKeyDown(Key.LeftShift) || Keyboard.IsKeyDown(Key.RightShift))
            {
                option.IsNewWindow = SwitchOption.on;
            }

            return option;
        }

        /// <summary>
        /// UserSetting 生成
        /// </summary>
        private UserSetting CreateUserSetting(UserSettingResource settingResource)
        {
            using var span = DebugSpan();
            try
            {
                var setting = settingResource.Load() ?? new UserSetting();
                return setting.EnsureConfig();
            }
            catch (Exception ex)
            {
                var dialog = new UserSettingLoadFailedDialog(true);
                var result = dialog.ShowDialog(ex);
                if (result != true)
                {
                    throw new OperationCanceledException();
                }
                return new UserSetting().EnsureConfig();
            }
        }

        /// <summary>
        /// バージョンダイアログを表示
        /// </summary>
        private void ShowVersionDialog()
        {
            var dialog = new VersionWindow() { WindowStartupLocation = WindowStartupLocation.CenterScreen };
            dialog.ShowDialog();
        }

        /// <summary>
        /// 言語リソース初期化
        /// </summary>
        /// <param name="language"></param>
        private void InitializeTextResource(string language)
        {
            using var span = DebugSpan();
            CultureInfo culture;
            try
            {
                culture = CultureInfo.GetCultureInfo(language);
            }
            catch (CultureNotFoundException)
            {
                culture = CultureInfo.CurrentCulture;
            }
            TextResources.Initialize(culture);
            InputGestureDisplayString.Initialize(TextResources.Resource);

            // 開発用：テキストリソース検証
            //TextResources.ValidateAllCultures();
        }

        /// <summary>
        /// ヘルプ用 HtmlNode 初期化
        /// </summary>
        private void InitializeHtmlNode()
        {
            HtmlNode.DefaultTextEvaluator = e => TextResources.Replace(e, true);
        }

        /// <summary>
        /// コマンドテーブル初期化
        /// </summary>
        private void InitializeCommandTable()
        {
            using var span = DebugSpan();
            _ = CommandTable.Current;
        }

        /// <summary>
        /// 画像拡張子初期化
        /// </summary>
        private void InitializeSupportFileType(Config config)
        {
            using var span = DebugSpan();
            if (config.Image.Standard.SupportFileTypes is null)
            {
                config.Image.Standard.SupportFileTypes = PictureFileExtensionTools.CreateDefaultSupportedFileTypes(config.Image.Standard.UseWicInformation);
            }
        }

        /// <summary>
        /// テンポラリーの場所
        /// </summary>
        private void InitializeTemporary(Config config)
        {
            using var span = DebugSpan();
            config.System.TemporaryDirectory = Temporary.Current.SetDirectory(config.System.TemporaryDirectory, true);
        }

        /// <summary>
        /// TextBox以外のコントロールのIMEキー設定
        /// </summary>
        private void InitializeImeKey(Config config)
        {
            using var span = DebugSpan();
            if (!config.System.IsInputMethodEnabled)
            {
                InputMethod.IsInputMethodEnabledProperty.OverrideMetadata(typeof(FrameworkElement), new FrameworkPropertyMetadata(false));
                InputMethod.IsInputMethodEnabledProperty.OverrideMetadata(typeof(System.Windows.Controls.TextBox), new FrameworkPropertyMetadata(true));
            }
        }

        /// <summary>
        /// テーマの初期化
        /// </summary>
        private void InitializeTheme()
        {
            using var span = DebugSpan();
            _ = ThemeManager.Current;
        }

        /// <summary>
        /// Show SplashScreen
        /// </summary>
        public void ShowSplashScreen(BootSetting bootSetting)
        {
            if (bootSetting.IsSplashScreenEnabled && CanStart(bootSetting.IsMultiBootEnabled) && !this.Option.IsVersion)
            {
                if (_isSplashScreenVisible) return;
                _isSplashScreenVisible = true;

                using var span = DebugSpan();
                var resourceName = "Resources/SplashScreen.png";
                var splashScreen = new SplashScreen(resourceName);
                splashScreen.Show(true, true);
            }
        }

        /// <summary>
        /// 多重起動用実行可能判定
        /// </summary>
        private bool CanStart(bool isMultiBootEnabled)
        {
            if (_multiBootService is null) return false;

            return !_multiBootService.IsServerExists || (Option.IsNewWindow != null ? Option.IsNewWindow == SwitchOption.on : isMultiBootEnabled);
        }

        /// <summary>
        /// 終了処理
        /// </summary>
        /// <param name="sender"></param>
        /// <param name="e"></param>
        private void Application_Exit(object sender, ExitEventArgs e)
        {
            Trace.WriteLine("App.Exit:");
            Terminate(true);
        }

        /// <summary>
        /// PCシャットダウン時に呼ばれる
        /// </summary>
        private void Application_SessionEnding(object sender, SessionEndingCancelEventArgs e)
        {
            Trace.WriteLine($"App.SessionEnding: {e.ReasonSessionEnding}");

            (this.MainWindow as MainWindow)?.FinalizeMainWindow();

            Terminate(false);
        }

        /// <summary>
        /// 終了時処理。設定の保存等
        /// </summary>
        private void Terminate(bool callProcessTerminator)
        {
            if (_isTerminated) return;
            _isTerminated = true;

            TerminateUnhandledException();

            try
            {
                // 現在のブックを履歴に保存
                PageFrameBoxPresenter.Current.ForceSaveBookMemento();
                PageFrameBoxPresenter.Current.SaveLastBookMemento();

                // 現在の本棚の場所を保存
                BookshelfFolderList.Current.SaveLastFolderPath();

                // 各種Dispose
                ApplicationDisposer.Current.Dispose();

                if (App.Current.IsMainWindowLoaded)
                {
                    // 設定保存
                    SaveDataSync.Current.DisposeWatcher();
                    SaveDataSync.Current.SaveAll(false, false);
                    SaveDataSync.Current.Dispose();
                    SaveData.Current.DisableSave();

                    // キャッシュDBのクリーンナップ
                    ThumbnailCache.Current.Cleanup();

                    // キャッシュDBを閉じる
                    ThumbnailCache.Current.Dispose();

                    // DBを閉じる
                    Database.DisposeIfExists();

                    // テンポラリファイル破棄
                    Temporary.Current.RemoveTempFolder();
                }

                Trace.WriteLine($"App.Terminate: {DateTime.Now}: Terminated.");
            }
            catch (Exception ex)
            {
                Debug.Assert(false, "Application Terminate failed!!");
                Trace.Fail($"App.Terminate: {DateTime.Now}: {ex.ToStackString()}");
                throw;
            }

            if (callProcessTerminator)
            {
                try
                {
                    CallProcessTerminator();
                }
                catch (Exception ex)
                {
                    Debug.Assert(false, "Cannot start Terminator.");
                    Trace.Fail($"Cannot start Terminator: {ex.Message}");
                }
            }
        }

        /// <summary>
        /// 自プロセスがゾンビ化しても停止させる処理。
        /// 現象ではPdfDocumentによってゾンビプロセス化してしまうため。
        /// </summary>
        /// <seealso href="https://github.com/microsoft/CsWinRT/issues/1249"/>
        private static void CallProcessTerminator()
        {
            // NOTE: PdfDocument を使用していないので不要
#if false
            // NOTE: PDFでWinRTのレンダラーを使用している場合のみ機能させる
            if (PdfArchiveConfig.GetPdfRenderer() != PdfRenderer.WinRT) return;

            var filename = Path.Combine(Environment.LibrariesPath, "Libraries\\NeeView.Terminator.exe");

            // 開発中は直接プロジェクトを参照する
            if (Environment.IsDevPackage)
            {
                filename = Path.GetFullPath(Path.Combine(Environment.AssemblyFolder, @"..\..\..\..\..\NeeView.Terminator\bin", Environment.PlatformName, Environment.ConfigType, @"net10.0\NeeView.Terminator.exe"));
            }

            // 5秒後にこのプロセスが残っていたら強制終了させる監視プロセスを発行
            int timeout = 5000;
            var process = Process.GetCurrentProcess();
            var info = new ProcessStartInfo();
            info.UseShellExecute = false;
            info.CreateNoWindow = true;
            info.FileName = filename;
            info.Arguments = $"{process.Id} \"{process.ProcessName}\" {process.StartTime.ToFileTime()} {timeout}";
            Process.Start(info);
#endif
        }


        /// <summary>
        /// 保存しないでアプリをシャットダウン
        /// </summary>
        public void ShutdownWithoutSave()
        {
            SaveData.Current.DisableSave();
            Shutdown();
        }


        #region Develop

        private IDisposable? DebugSpan([CallerMemberName] string callerMethodName = "")
        {
#if DEBUG
            return new DebugSpanScope(Stopwatch, "App." + callerMethodName);
#else
            return null;
#endif
        }

        [Conditional("DEBUG")]
        private void DebugStamp(string label)
        {
            DebugSpanScope.Dump(Stopwatch, "App." + label);
        }

        #endregion Develop
    }

