        /// </remarks>
        public virtual ArchiveEntry TargetArchiveEntry => this;

        /// <summary>
        /// アーカイブヒント
        /// </summary>
        /// <remarks>
        /// このエントリからアーカイブを開くときに使用されます。
        /// </remarks>
        [NotNull]
        public ArchiveHint? ArchiveHint
        {
            get => _archiveHint ?? Archive.ArchiveHint;
            set => _archiveHint = value;
        }

        /// <summary>
        /// 暗号化されたエントリ
        /// </summary>
        public bool Encrypted { get; init; }


        protected virtual void Dispose(bool disposing)
        {
            if (!_disposedValue)
            {
                if (disposing)
                {
                    _preExtractMemoryKey?.Dispose();
                }
                _disposedValue = true;
            }
        }

        public void Dispose()
        {
            Dispose(disposing: true);
            GC.SuppressFinalize(this);
        }

        /// <summary>
        /// エントリ名の正規化
        /// </summary>
        public static string NormalizeEntryName(string rawEntryName)
        {
            return LoosePath.TrimEnd(LoosePath.NormalizeSeparator(rawEntryName));
        }

        /// <summary>
        /// エントリデータ設定
        /// </summary>
        /// <param name="value"></param>
        public void SetData(object value)
        {
            if (_disposedValue) return;

            lock (_lock)
            {
                if (_data == value) return;
                ResetData();
                if (value is null) return;
                _data = value;
                if (value is byte[] rawData)
                {
                    _preExtractMemoryKey = PreExtractMemory.Current.Open(rawData.Length);
                }
            }
            DataChanged?.Invoke(this, EventArgs.Empty);
        }

        /// <summary>
        /// エントリーデータリセット
        /// </summary>
        public void ResetData()
        {
            lock (_lock)
            {
                if (_data is null) return;
                _preExtractMemoryKey?.Dispose();
                _preExtractMemoryKey = null;
                _data = null;
            }
        }

        /// <summary>
        /// ストリームを開く
        /// </summary>
        /// <returns>Stream</returns>
        public async ValueTask<Stream> OpenEntryAsync(bool decrypt, CancellationToken token)
        {
            return await Archive.OpenStreamAsync(this, decrypt, token);
        }

        /// <summary>
        /// ファイルに出力する
        /// </summary>
        /// <param name="exportFileName">出力ファイル名</param>
        /// <param name="isOverwrite">上書き許可フラグ</param>
        public async ValueTask ExtractToFileAsync(string exportFileName, bool isOverwrite, CancellationToken token)
        {
            if (exportFileName is null) throw new ArgumentNullException(nameof(exportFileName));

            await Archive.ExtractToFileAsync(this, exportFileName, isOverwrite, token);
        }


        /// <summary>
        /// テンポラリにアーカイブエントリを解凍する
        /// このテンポラリは自動的に削除される
        /// </summary>
        /// <param name="entry"></param>
        /// <param name="isKeepFileName">エントリー名をファイル名にする</param>
        public async ValueTask<FileProxy> GetFileProxyAsync(bool isKeepFileName, CancellationToken token)
        {
            _fileProxy = _fileProxy ?? await CreateFileProxyAsync(new TempFileNamePolicy(isKeepFileName, "entry"), false, token);
            return _fileProxy;
        }

        /// <summary>
        /// テンポラリアーカイブエントリを得る。
        /// 場合によっては存在するファイルをそのまま返す。
        /// </summary>
        /// <param name="fileNamePolicy">ファイル名ポリシ―</param>
        /// <param name="isOverwrite">上書き許可</param>
        /// <returns>ファイル</returns>
        public async ValueTask<FileProxy> CreateFileProxyAsync(TempFileNamePolicy fileNamePolicy, bool isOverwrite, CancellationToken token)
        {
            var entityPath = EntityPath;
            if (entityPath is not null)
            {
                return new FileProxy(entityPath);
            }

            await WaitPreExtractAsync(token);

            var tempFileName = this.Archive.CreateTempFileName(this, fileNamePolicy);

            if (this.Data is string fileName)
            {
                if (fileNamePolicy.IsKeepFileName && fileName != tempFileName)
                {
                    await FileIO.CopyFileAsync(fileName, tempFileName, isOverwrite, false, token);
                    return new TempFile(tempFileName);
                }
                else
                {
                    return new FileProxy(fileName);
                }
            }
            else if (this.Data is byte[] rawData)
            {
                FileIO.CheckOverwrite(tempFileName, isOverwrite);
                await File.WriteAllBytesAsync(tempFileName, rawData, token);
                await this.Archive.WriteZoneIdentifierAsync(tempFileName, token);
                return new TempFile(tempFileName);
            }
            else
            {
                await ExtractToFileAsync(tempFileName, isOverwrite, token);
                return new TempFile(tempFileName);
            }
        }

        /// <summary>
        /// エントリ単位で事前展開完了を待機する
        /// </summary>
        /// <param name="token"></param>
        /// <returns></returns>
        public async ValueTask WaitPreExtractAsync(CancellationToken token)
        {
            await Archive.WaitPreExtractAsync(this, token);
        }


        /// <summary>
        /// アーカイブ判定
        /// </summary>
        /// <param name="isAllowFileSystem"></param>
        /// <param name="isAllowMedia"></param>
        /// <returns></returns>
        public bool IsArchiveSupported(bool isAllowFileSystem = true, bool isAllowMedia = true)
        {
            return ArchiveManager.Current.IsSupported(TargetPath, isAllowFileSystem, isAllowMedia);
        }

        /// <summary>
        /// アーカイブタイプ取得
        /// </summary>
        /// <returns></returns>
        public ArchiveType GetArchiveSupportedType()
        {
            return ArchiveManager.Current.GetSupportedType(TargetPath);
        }

        /// <summary>
        /// このエントリがブックであるかを判定。
        /// アーカイブのほかメディアを含める
        /// </summary>
        public bool IsBook()
        {
            if (this.IsDirectory)
            {
                return true;
            }

            return IsArchiveSupported(false, true);
        }

        /// <summary>
        /// このエントリがアーカイブであるかを判定。
        /// メディアは除外する
        /// </summary>
        public virtual bool IsArchive()
        {
            if (this.IsDirectory)
            {
                return this.IsFileSystem; // アーカイブディレクトリは除外
            }

            return IsArchiveSupported(false, false);
        }

        /// <summary>
        /// アーカイブ中のディレクトリ？
        /// </summary>
        public bool IsArchiveDirectory()
        {
            return !IsFileSystem && IsDirectory;
        }

        /// <summary>
        /// メディア？
        /// </summary>
        public bool IsMedia()
        {
            return !this.IsDirectory && GetArchiveSupportedType() == ArchiveType.MediaArchive;
        }

        /// <summary>
        /// このエントリが画像であるか拡張子から判定。
        /// MediaArchive は無条件で画像と認識
        /// </summary>
        public bool IsImage(bool includeMedia = true)
        {
            return !this.IsDirectory && ((this.Archive is MediaArchive) || PictureProfile.Current.IsSupported(TargetPath, includeMedia));
        }

        /// <summary>
        /// exists?
        /// </summary>
        public bool Exists()
        {
            if (IsDeleted) return false;
            return Archive.Exists(this);
        }

        /// <summary>
        /// can delete?
        /// </summary>
        public bool CanDelete(bool strict)
        {
            return Archive.CanDelete(this, strict);
        }

        /// <summary>
        /// delete
        /// </summary>
        public async ValueTask<DeleteResult> DeleteAsync()
        {
            return await Archive.DeleteAsync(this);
        }

        /// <summary>
        /// 複数エントリをまとめて削除
        /// </summary>
        public static async ValueTask<bool> DeleteEntriesAsync(IEnumerable<ArchiveEntry> entries)
        {
            if (!entries.Any()) return false;

            foreach (var group in entries.GroupBy(e => e.Archive))
            {
                var archiver = group.Key;
                var result = await archiver.DeleteAsync(group.ToList());
                if (result < 0) return false;
            }

            return true;
        }

        /// <summary>
        /// to string
        /// </summary>
        public override string? ToString()
        {
            return string.IsNullOrEmpty(EntryName) ? base.ToString() : $"{Id}:{EntryName}";
        }


        public string GetRenameText()
        {
            return EntryLastName;
        }

        public bool CanRename()
        {
            return Archive.CanRename(this);
        }

        public async ValueTask<bool> RenameAsync(string name)
        {
            return await Archive.RenameAsync(this, name);
        }

        /// <summary>
        /// エントリの実体化は可能か？
        /// </summary>
        public bool CanRealize()
        {
            return Archive.CanRealize(this);
        }

        /// <summary>
        /// エントリを実体ファイルにする
        /// </summary>
        /// <param name="token"></param>
        /// <returns>実体ファイルのパス</returns>
        /// <exception cref="ArgumentException"></exception>
        /// <exception cref="InvalidOperationException"></exception>
        /// <exception cref="NotSupportedException"></exception>
        public async ValueTask<string?> RealizeAsync(CancellationToken token)
        {
            var archivePolicy = Config.Current.System.ArchiveCopyPolicy.LimitedRealization();
            return await RealizeAsync(archivePolicy, token);
        }

        /// <summary>
        /// エントリを実体ファイルにする
        /// </summary>
        /// <param name="archivePolicy">アーカイブファイルのときの方針</param>
        /// <param name="token"></param>
        /// <returns>実体ファイルのパス。取得できなかったときは null</returns>
        /// <exception cref="NotSupportedException">サポートされていない ArchivePolicy</exception>
        public virtual async ValueTask<string?> RealizeAsync(ArchivePolicy archivePolicy, CancellationToken token)
        {
            // file
            if (IsFileSystem)
            {
                // NOTE: ショートカットもそのまま渡すよ
                return SystemPath;
            }

            // in archive
            switch (archivePolicy)
            {
                case ArchivePolicy.None:
                    return null;

                case ArchivePolicy.SendArchiveFile:
                    return PlacePath;

                case ArchivePolicy.SendExtractFile:
                    if (CanRealize())
                    {
                        var proxy = await GetFileProxyAsync(true, token);
                        return proxy.Path;
                    }
                    else
                    {
                        // TODO: ArchiveDirectory 対応
                        return null;
                    }

                case ArchivePolicy.SendArchivePath:
                    return SystemPath;

                default:
                    throw new NotSupportedException($"Unsupported archive policy: {archivePolicy}");
            }
        }

        /// <summary>
        /// シンボリックリンクを解決したファイル情報を返す
        /// </summary>
        /// <remarks>
        /// ファイルシステム限定
        /// </remarks>
        /// <returns></returns>
        public virtual FileSystemInfo? ResolveLinkTarget()
        {
            return null;
        }

    }


    public enum ArchiveEntryAttributes
    {
        None = 0,

        /// <summary>
        /// エントリ名が重複した別エントリが存在する
        /// </summary>
        Duplicate = (1 << 0),

        /// <summary>
        /// 共通指定ブックサムネイル用エントリ
        /// </summary>
        SpecifiedBookThumbnail = (1 << 1),

        /// <summary>
        /// 個別指定ブックサムネイル用エントリ
        /// </summary>
        IndividualBookThumbnail = (1 << 2),
    }
}

﻿using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{

    /// <summary>
    /// 指定パス以下のArchiveEntryの収集
    /// </summary>
    public class ArchiveEntryCollection
    {
        private readonly ArchiveEntryCollectionMode _mode;
        private readonly ArchiveEntryCollectionMode _modeIfArchive;
        private readonly bool _ignoreCache;
        private readonly ArchiveHint _archiveHint;
        private List<ArchiveEntryNode>? _entries;

        /// <summary>
        /// コンストラクタ
        /// </summary>
        /// <param name="path">対象のパス</param>
        /// <param name="mode">標準再帰モード</param>
        /// <param name="modeIfArchive">圧縮ファイルの再帰モード</param>
        /// <param name="option"></param>
        public ArchiveEntryCollection(string path, ArchiveEntryCollectionMode mode, ArchiveEntryCollectionMode modeIfArchive, ArchiveEntryCollectionOption option, ArchiveHint archiveHint)
        {
            Path = LoosePath.TrimEnd(path);
            Mode = mode;
            _mode = mode;
            _modeIfArchive = modeIfArchive;
            _ignoreCache = option.HasFlag(ArchiveEntryCollectionOption.IgnoreCache);
            _archiveHint = archiveHint;
        }

        public string Path { get; }
        public Archive? Archive { get; private set; }

        public ArchiveEntryCollectionMode Mode { get; private set; }

        /// <summary>
        /// ArchiveEntry収集
        /// </summary>
        public async ValueTask<List<ArchiveEntryNode>> GetEntriesAsync(bool decrypt, CancellationToken token)
        {
            if (_entries != null) return _entries;

            var rootEntry = await ArchiveEntryUtility.CreateAsync(Path, _archiveHint, decrypt, token);

            Archive? rootArchive;
            string rootArchivePath;

            if (rootEntry.IsFileSystem)
            {
                if (rootEntry.IsDirectory)
                {
                    rootArchive = await ArchiveManager.Current.CreateArchiveAsync(StaticFolderArchive.Default.CreateArchiveEntry(Path, _archiveHint), _ignoreCache, token);
                    rootArchivePath = "";
                }
                else
                {
                    rootArchive = await ArchiveManager.Current.CreateArchiveAsync(rootEntry, _ignoreCache, token);
                    rootArchivePath = "";
                }
            }
            else
            {
                if (rootEntry.IsArchive() || rootEntry.IsMedia())
                {
                    rootArchive = await ArchiveManager.Current.CreateArchiveAsync(rootEntry, _ignoreCache, token);
                    rootArchivePath = "";
                }
                else
                {
                    rootArchive = rootEntry.Archive;
                    rootArchivePath = rootEntry.EntryName;
                }
            }

            if (rootArchive is null)
            {
                return new List<ArchiveEntryNode>() { new ArchiveEntryNode(null, rootEntry) };
            }

            Archive = rootArchive;

            Mode = (Archive is FolderArchive || Archive is PlaylistArchive) ? _mode : _modeIfArchive;

            var includeSubDirectories = Mode == ArchiveEntryCollectionMode.IncludeSubDirectories || Mode == ArchiveEntryCollectionMode.IncludeSubArchives;
            var entries = (await rootArchive.GetEntriesAsync(rootArchivePath, includeSubDirectories, decrypt, token)).Select(e => new ArchiveEntryNode(null, e, rootArchivePath)).ToList();

            var includeAllSubDirectories = Mode == ArchiveEntryCollectionMode.IncludeSubArchives;
            if (includeAllSubDirectories)
            {
                entries = await GetSubArchivesEntriesAsync(entries, decrypt, token);
            }

            _entries = entries;
            return _entries;
        }


        private async ValueTask<List<ArchiveEntryNode>> GetSubArchivesEntriesAsync(List<ArchiveEntryNode> entries, bool decrypt, CancellationToken token)
        {
            var result = new List<ArchiveEntryNode>();

            foreach (var entry in entries)
            {
                result.Add(entry);

                if (entry.ArchiveEntry.IsArchive())
                {
                    // 無限ループを避けるためショートカットは除外する
                    if (entry.ArchiveEntry.IsShortcut)
                    {
                        continue;
                    }

                    try
                    {
                        var entityEntry = entry.ArchiveEntry.TargetArchiveEntry;
                        var subArchive = await ArchiveManager.Current.CreateArchiveAsync(entityEntry, _ignoreCache, token);
                        var subEntries = (await subArchive.GetEntriesAsync(decrypt, token)).Select(e => new ArchiveEntryNode(entry, e)).ToList();
                        result.AddRange(await GetSubArchivesEntriesAsync(subEntries, decrypt, token));
                    }
                    catch (OperationCanceledException)
                    {
                        throw;
                    }
                    catch (Exception ex)
                    {
                        Debug.WriteLine(ex.Message);
                        Debug.WriteLine($"ArchiveEntryCollection.Skip: {entry.ArchiveEntry.EntryName}");
                    }
                }
            }

            return result;
        }


        // filter: ページとして画像ファイルのみリストアップ
        public async ValueTask<List<ArchiveEntryNode>> GetEntriesWhereImageAsync(bool decrypt, CancellationToken token)
        {
            var entries = await GetEntriesAsync(decrypt, token);
            return entries.Where(e => e.ArchiveEntry.IsImage()).ToList();
        }

        // filter: ページとして画像ファイルとアーカイブをリストアップ
        public async ValueTask<List<ArchiveEntryNode>> GetEntriesWhereImageAndArchiveAsync(bool decrypt, CancellationToken token)
        {
            var entries = await GetEntriesAsync(decrypt, token);
            if (Mode == ArchiveEntryCollectionMode.CurrentDirectory)
            {
                return entries.Where(e => e.ArchiveEntry.IsImage() || e.ArchiveEntry.IsBook()).ToList();
            }
            else
            {
                return entries.WherePageAll().Where(e => e.ArchiveEntry.IsImage() || e.ArchiveEntry.IsBook()).ToList();
            }
        }

        // filter: ページとしてすべてのファイルをリストアップ。フォルダーは空きフォルダーのみリストアップ
        public async ValueTask<List<ArchiveEntryNode>> GetEntriesWherePageAllAsync(bool decrypt, CancellationToken token)
        {
            var entries = await GetEntriesAsync(decrypt, token);
            return entries.WherePageAll().ToList();
        }

        // filter: 含まれるサブアーカイブのみ抽出
        public async ValueTask<List<ArchiveEntryNode>> GetEntriesWhereSubArchivesAsync(bool decrypt, CancellationToken token)
        {
            var entries = await GetEntriesAsync(decrypt, token);
            return entries.Where(e => e.ArchiveEntry.IsArchive() || e.ArchiveEntry.IsMedia()).ToList();
        }

        // filter: 含まれるブックを抽出
        public async ValueTask<List<ArchiveEntryNode>> GetEntriesWhereBookAsync(bool decrypt, CancellationToken token)
        {
            var entries = await GetEntriesAsync(decrypt, token);
            if (Mode == ArchiveEntryCollectionMode.CurrentDirectory)
            {
                return entries.Where(e => e.ArchiveEntry.IsBook()).ToList();
            }
            else
            {
                return entries.Where(e => e.ArchiveEntry.IsBook() && !e.ArchiveEntry.IsArchiveDirectory()).ToList();
            }
        }

        /// <summary>
        /// フォルダーリスト上での親フォルダーを取得
        /// </summary>
        public string? GetFolderPlace()
        {
            if (Path == null || Archive == null)
            {
                return null;
            }

            if (Archive == null)
            {
                Debug.Assert(false, "Invalid operation");
                return null;
            }

            if (Mode == ArchiveEntryCollectionMode.IncludeSubArchives)
            {
                return LoosePath.GetDirectoryName(Archive.RootArchive?.SystemPath);
            }
            else if (Mode == ArchiveEntryCollectionMode.IncludeSubDirectories)
            {
                if (Archive.Parent != null)
                {
                    return Archive.Parent.SystemPath;
                }
                else
                {
                    return LoosePath.GetDirectoryName(Archive.SystemPath);
                }
            }
            else
            {
                return LoosePath.GetDirectoryName(Path);
            }
        }
    }

    public static class ArchiveEntryCollectionExtensions
    {
        /// <summary>
        /// filter: ディレクトリとなるエントリをすべて除外
        /// </summary>
        public static IEnumerable<ArchiveEntryNode> WherePageAll(this IEnumerable<ArchiveEntryNode> source)
        {
            var directories = source.Select(e => LoosePath.GetDirectoryName(e.ArchiveEntry.SystemPath)).Distinct().ToList();
            return source.Where(e => e.ArchiveEntry.IsShortcut || !directories.Contains(e.ArchiveEntry.SystemPath));
        }

        /// <summary>
        /// ArchiveEntryNode リストから ArchiveEntry リストを取得する
        /// </summary>
        public static List<ArchiveEntry> ToArchiveEntryCollection(this IEnumerable<ArchiveEntryNode> source)
        {
            return source.Select(e => e.ArchiveEntry).ToList();
        }
    }
}

﻿using System;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    /// <summary>
    /// ArchiveEntryからファイルに展開する。キャンセル可。
    /// </summary>
    public class ArchiveEntryExtractor : IDisposable
    {
        private static TempFileNamePolicy _namePolicy = new(false, "arcv");

        private readonly ArchiveEntry _entry;
        private readonly Task _task;
        private FileProxy? _tempFile;
        private bool _disposedValue;

        // TODO: いきなり処理が始まっているのはよろしくない。実行は別メソッドで。
        public ArchiveEntryExtractor(ArchiveEntry entry)
        {
            _entry = entry;

            _task = Task.Run(async () =>
            {
                _tempFile = await _entry.CreateFileProxyAsync(_namePolicy, false, CancellationToken.None); // ## TODO cancellationToken
            });

            _task.ContinueWith(async (t) =>
            {
                await Task.Delay(1000);
                Expired?.Invoke(this, new(_entry, t.Exception));
            });
        }

        // 期限切れ
        public event EventHandler<ArchiveEntryExtractorExpiredEventArgs>? Expired;


        public async ValueTask<FileProxy> WaitAsync(CancellationToken token)
        {
            ThrowIfDisposed();

            await _task.WaitAsync(token);

            var tempFile = Interlocked.Exchange(ref _tempFile, null);
            if (tempFile is null) throw new InvalidOperationException();

            //Debug.WriteLine($"## Export: {_extractFileName}");
            return tempFile;
        }


        protected void ThrowIfDisposed()
        {
            if (_disposedValue) throw new ObjectDisposedException(GetType().FullName);
        }

        protected virtual void Dispose(bool disposing)
        {
            if (!_disposedValue)
            {
                if (disposing)
                {
                    var tempFile = Interlocked.Exchange(ref _tempFile, null);
                    tempFile?.Dispose();
                }

                //Debug.WriteLine($"## Disposed: {_extractFileName}");
                _disposedValue = true;
            }
        }

        public void Dispose()
        {
            Dispose(disposing: true);
            GC.SuppressFinalize(this);
        }
    }
}

﻿using System;
using System.Collections.Generic;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    /// <summary>
    /// ArchiveEntryExtractor管理
    /// キャンセルされたがまだ処理が残っているインスタンスの再利用
    /// </summary>
    public class ArchiveEntryExtractorService
    {
        static ArchiveEntryExtractorService() => Current = new ArchiveEntryExtractorService();
        public static ArchiveEntryExtractorService Current { get; }


        // lock object
        private readonly System.Threading.Lock _lock = new();

        /// <summary>
        /// キャンセルされたが処理中のインスタンス群
        /// </summary>
        private readonly Dictionary<string, ArchiveEntryExtractor> _collection = new();



        /// <summary>
        /// 指定したキーの削除
        /// </summary>
        /// <returns>削除されたオブジェクトを返す。ない場合は null</returns>
        private ArchiveEntryExtractor? Remove(string key)
        {
            lock (_lock)
            {
                if (_collection.Remove(key, out var extractor))
                {
                    return extractor;
                }
                else
                {
                    return null;
                }
            }
        }

        /// <summary>
        /// キーの追加
        /// </summary>
        private void Add(string key, ArchiveEntryExtractor extractor)
        {
            lock (_lock)
            {
                _collection.Add(key, extractor);
            }
        }


        /// <summary>
        /// 展開
        /// テンポラリファイルはキャッシュを活用する
        /// </summary>
        public async ValueTask<FileProxy> ExtractAsync(ArchiveEntry entry, CancellationToken token)
        {
            var cachedTempFile = TempFileCache.Current.Get(entry.Ident);
            if (cachedTempFile != null) return cachedTempFile;

            var proxyFile = await ExtractRawAsync(entry, token);
            if (proxyFile is TempFile tempFile)
            {
                TempFileCache.Current.Add(entry.Ident, tempFile);
            }
            return proxyFile;
        }

        /// <summary>
        /// 展開
        /// ファイルはテンポラリに生成される
        /// </summary>
        /// <returns>展開後されたファイル名</returns>
        public async ValueTask<FileProxy> ExtractRawAsync(ArchiveEntry entry, CancellationToken token)
        {
            //Debug.WriteLine($"EXT: {entry.Ident}");

            ArchiveEntryExtractor? extractor = null;
            try
            {
                extractor = this.Remove(entry.Ident);
                if (extractor == null)
                {
                    //Debug.WriteLine($"EXT:{entry.Ident} Create");
                    extractor = new ArchiveEntryExtractor(entry);
                    extractor.Expired += Extractor_Expired;
                }
                var proxyFile = await extractor.WaitAsync(token);
                extractor.Dispose();
                return proxyFile;
            }
            catch (OperationCanceledException)
            {
                //Debug.WriteLine($"EXT: {entry.Ident} Add to reservoir");
                if (extractor != null)
                {
                    this.Add(entry.Ident, extractor);
                }
                throw;
            }
        }

        // 期限切れ処理
        private void Extractor_Expired(object? sender, ArchiveEntryExtractorExpiredEventArgs args)
        {
            if (args.ArchiveEntry is null) return;

            //Debug.WriteLine($"EXT: Remove {entry.Ident}");
            var extractor = Remove(args.ArchiveEntry.Ident);
            extractor?.Dispose();
        }
    }
}

﻿using System.Diagnostics;

namespace NeeView
{
    /// <summary>
