﻿using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;

namespace NeeView
{
    /// <summary>
    /// ArchiveEntryのフォルダー構造作成。
    /// ArchiveEntryを追加することによって階層を構成していく。
    /// 階層構造のみ、ArchiveEntryのリーフは持たない。
    /// </summary>
    public class ArchiveEntryTree
    {
        private readonly ArchiveEntryTreeNode _root;

        public ArchiveEntryTree()
        {
            _root = new ArchiveEntryTreeNode();
        }

        public void AddRange(IEnumerable<ArchiveEntry> entries)
        {
            foreach (var entry in entries)
            {
                Add(entry);
            }
        }

        public void Add(ArchiveEntry entry)
        {
            var path = entry.IsDirectory ? entry.EntryName : LoosePath.GetDirectoryName(entry.EntryName);
            var parts = LoosePath.Split(path);

            var node = _root;
            foreach (var part in parts)
            {
                var child = node.Children?.FirstOrDefault(e => e.Name == part);
                if (child == null)
                {
                    child = new ArchiveEntryTreeNode(node, part);
                    node.Children?.Add(child);
                }

                child.CreationTime = entry.CreationTime;
                child.LastWriteTime = entry.LastWriteTime;

                node = child;
            }

            if (entry.IsDirectory)
            {
                Debug.Assert(entry.EntryName == ArchiveEntry.NormalizeEntryName(node.Path));
                node.ArchiveEntry = entry;
            }
        }

        public List<ArchiveEntryTreeNode> GetDirectories()
        {
            return _root.Where(e => e != _root).ToList();
        }

        [Conditional("DEBUG")]
        public void Dump()
        {
            Debug.WriteLine("");
            foreach (var dir in GetDirectories())
            {
                Debug.WriteLine($"Directory: {dir.Path}: ({dir.Children.Count})");
            }
        }
    }
}

﻿using System;
using System.Collections;
using System.Collections.Generic;

namespace NeeView
{
    /// <summary>
    /// ArchiveEntryTree用ノード
    /// </summary>
    public class ArchiveEntryTreeNode : IEnumerable<ArchiveEntryTreeNode>
    {
        public ArchiveEntryTreeNode()
        {
            Parent = null;
            Name = "";
        }

        public ArchiveEntryTreeNode(ArchiveEntryTreeNode parent, string name)
        {
            Parent = parent;
            Name = name;
        }

        public string Name { get; private set; }

        public DateTime CreationTime { get; set; }
        public DateTime LastWriteTime { get; set; }
        public ArchiveEntryTreeNode? Parent { get; private set; }
        public List<ArchiveEntryTreeNode> Children { get; private set; } = new List<ArchiveEntryTreeNode>();

        public string Path => LoosePath.Combine(Parent?.Path, Name);

        /// <summary>
        /// ArchiveEntryが存在する場合の入れ物
        /// </summary>
        public ArchiveEntry? ArchiveEntry { get; set; }


        public IEnumerator<ArchiveEntryTreeNode> GetEnumerator()
        {
            yield return this;
            foreach (var child in Children)
            {
                foreach (var subChild in child)
                {
                    yield return subChild;
                }
            }
        }

        IEnumerator IEnumerable.GetEnumerator()
        {
            return GetEnumerator();
        }
    }
}

﻿using NeeView.Properties;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Globalization;
using System.IO;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    /// <summary>
    /// アーカイブ内パスを含むパス記述に対応した処理
    /// </summary>
    public static class ArchiveEntryUtility
    {
        /// <summary>
        /// 仮エントリ―作成
        /// </summary>
        /// <remarks>
        /// 指定したパスがファイルシステム上に存在すると仮定して発行する。アーカイブ内等の実エントリーにするにはCreateAsync()を使用する。
        /// </remarks>
        /// <param name="path"></param>
        /// <returns></returns>
        public static ArchiveEntry CreateTemporaryEntry(string path)
        {
            return StaticFolderArchive.Default.CreateArchiveEntry(path, ArchiveHint.None, true);
        }


        /// <summary>
        /// パスから完全なArchiveEntryを作成
        /// </summary>
        public static async ValueTask<ArchiveEntry> CreateAsync(string path, ArchiveHint archiveHint, bool decrypt, CancellationToken token)
        {
            token.ThrowIfCancellationRequested();

            var query = new QueryPath(path);

            if (File.Exists(path) || Directory.Exists(path))
            {
                return StaticFolderArchive.Default.CreateArchiveEntry(path, archiveHint);
            }
            else
            {
                try
                {
                    var parts = LoosePath.Split(path);
                    string? archivePath = null;

                    foreach (var part in parts)
                    {
                        archivePath = LoosePath.Combine(archivePath, part);

                        if (File.Exists(archivePath))
                        {
                            var archive = await ArchiveManager.Current.CreateArchiveAsync(StaticFolderArchive.Default.CreateArchiveEntry(archivePath, archiveHint), false, token);
                            var entries = await archive.GetEntriesAsync(decrypt, token);

                            // メディア アーカイブの場合、ページ指定は無効
                            if (archive is MediaArchive)
                            {
                                return entries.First();
                            }

                            var entryName = path[archivePath.Length..].TrimStart(LoosePath.Separators);
                            var entry = entries.FirstOrDefault(e => e.EntryName == entryName);
                            if (entry != null)
                            {
                                return entry;
                            }
                            else
                            {
                                return await CreateInnerAsync(archive, entryName, decrypt, token);
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                    throw new FileNotFoundException(string.Format(CultureInfo.InvariantCulture, TextResources.GetString("FileNotFoundException.Message"), path), ex);
                }
            }

            throw new FileNotFoundException(string.Format(CultureInfo.InvariantCulture, TextResources.GetString("FileNotFoundException.Message"), path));
        }

        /// <summary>
        /// アーカイブ内のエントリーを返す。
        /// 入れ子になったアーカイブの場合、再帰処理する。
        /// </summary>
        private static async ValueTask<ArchiveEntry> CreateInnerAsync(Archive archive, string entryName, bool decrypt, CancellationToken token)
        {
            token.ThrowIfCancellationRequested();

            var entries = await archive.GetEntriesAsync(decrypt, token);

            var entry = entries.FirstOrDefault(e => e.EntryName == entryName);
            if (entry != null) return entry;

            var parts = LoosePath.Split(entryName);
            string? archivePath = null;

            foreach (var part in parts)
            {
                archivePath = LoosePath.Combine(archivePath, part);

                entry = entries.FirstOrDefault(e => e.EntryName == archivePath && e.IsArchive());
                if (entry != null)
                {
                    var subArchive = await ArchiveManager.Current.CreateArchiveAsync(entry, false, token);
                    var subEntryName = entryName[archivePath.Length..].TrimStart(LoosePath.Separators);
                    return await CreateInnerAsync(subArchive, subEntryName, decrypt, token);
                }
            }

            throw new FileNotFoundException();
        }

        /// <summary>
        /// ブックサムネイルに使用するエントリを取得
        /// </summary>
        /// <param name="source">対象のエントリ</param>
        /// <param name="depth">検索範囲</param>
        public static async ValueTask<ArchiveEntry?> CreateFirstImageArchiveEntryAsync(ArchiveEntry source, string fileName, int depth, bool decrypt, CancellationToken token)
        {
            token.ThrowIfCancellationRequested();

            try
            {
                if (ArchiveManager.Current.GetSupportedType(source.SystemPath) == ArchiveType.MediaArchive)
                {
                    return source;
                }

                List<ArchiveEntry> entries;
                if (!source.IsFileSystem && source.IsDirectory)
                {
                    entries = (await source.Archive.GetEntriesAsync(decrypt, token))
                        .Where(e => e.EntryName.StartsWith(LoosePath.TrimDirectoryEnd(source.EntryName), StringComparison.Ordinal))
                        .ToList();
                }
                else
                {
                    var archiver = await ArchiveManager.Current.CreateArchiveAsync(source, false, token);
                    await archiver.WaitFileReadableAsync(TimeSpan.FromMilliseconds(1000), token);
                    entries = await archiver.GetEntriesAsync(decrypt, token);
                }

                // NOTE: ToList()で確定させる。もともとList<>であるが、これがないと次の行以降で Collection was modified; enumeration operation may not execute が発生することがある
                // TODO: 原因の調査
                entries = EntrySort.SortEntries(entries, PageSortMode.FileName).ToList();

                // 指定ファイル名を取得
                if (!string.IsNullOrEmpty(fileName))
                {
                    var thumb = entries.FirstOrDefault(e => string.Compare(e.EntryLastName, fileName, StringComparison.OrdinalIgnoreCase) == 0);
                    if (thumb != null)
                    {
                        thumb.Attributes |= ArchiveEntryAttributes.SpecifiedBookThumbnail;
                        return thumb;
                    }
                }

                // メディアを除外した最初の画像ページを取得
                var select = entries.FirstOrDefault(e => e.IsImage(false));
                if (select != null)
                {
                    return select;
                }

                if (depth > 1)
                {
                    // NOTE: 検索サブディレクトリ数も depth で制限
                    foreach (var entry in entries.Where(e => e.IsArchive()).Take(depth))
                    {
                        select = await CreateFirstImageArchiveEntryAsync(entry, fileName, depth - 1, decrypt, token);
                        if (select != null)
                        {
                            return select;
                        }
                    }
                }
            }
            catch (OperationCanceledException)
            {
                throw;
            }
            catch (Exception ex)
            {
                Debug.WriteLine(ex.Message);
            }

            return null;
        }

        /// <summary>
        /// アーカイブパスの存在チェック
        /// </summary>
        /// <param name="path"></param>
        /// <param name="token"></param>
        /// <returns></returns>
        public static async ValueTask<bool> ExistsAsync(string path, bool decrypt, CancellationToken token)
        {
            token.ThrowIfCancellationRequested();

            try
            {
                var entry = await CreateAsync(path, ArchiveHint.None, decrypt, token);
                return entry != null;
            }
            catch (FileNotFoundException)
            {
                return false;
            }
        }


        /// <summary>
        /// 実在するディレクトリまで遡る
        /// </summary>
        /// <param name="path"></param>
        /// <returns></returns>
        public static string? GetExistDirectoryName(string path)
        {
            if (Directory.Exists(path))
            {
                return path;
            }

            while (!string.IsNullOrEmpty(path))
            {
                path = LoosePath.GetDirectoryName(path);
                if (Directory.Exists(path))
                {
                    return path;
                }
            }

            return null;
        }

        /// <summary>
        /// 実在するエントリーまで遡る
        /// </summary>
        /// <param name="path"></param>
        /// <returns></returns>
        public static string? GetExistEntryName(string path)
        {
            if (Directory.Exists(path) || File.Exists(path))
            {
                return path;
            }

            while (!string.IsNullOrEmpty(path))
            {
                path = LoosePath.GetDirectoryName(path);
                if (Directory.Exists(path) || File.Exists(path))
                {
                    return path;
                }
            }

            return null;
        }

        /// <summary>
        /// エントリ群の実体化
        /// </summary>
        /// <param name="entries">エントリ群</param>
        /// <param name="token"></param>
        /// <returns>実体化されたファイルパス</returns>
        public static async ValueTask<List<string>> RealizeArchiveEntry(IEnumerable<ArchiveEntry> entries, CancellationToken token)
        {
            var archivePolicy = Config.Current.System.ArchiveCopyPolicy.LimitedRealization();
            return await RealizeArchiveEntry(entries, archivePolicy, token);
        }

        /// <summary>
        /// エントリ群の実体化
        /// </summary>
        /// <param name="entries">エントリ群</param>
        /// <param name="archivePolicy">実ファイルでなくアーカイブエントリである場合の方針</param>
        /// <param name="token"></param>
        /// <returns>実体化されたファイルパス</returns>
        public static async ValueTask<List<string>> RealizeArchiveEntry(IEnumerable<ArchiveEntry> entries, ArchivePolicy archivePolicy, CancellationToken token)
        {
            var paths = new List<string>();
            foreach (var entry in entries)
            {
                var path = await entry.RealizeAsync(archivePolicy, token);
                if (path is not null)
                {
                    paths.Add(path);
                }
            }
            return paths.Distinct().ToList();
        }

        /// <summary>
        /// ページ削除用エントリの種類を取得
        /// </summary>
        public static DeleteEntryType GetDeleteEntryType(IEnumerable<ArchiveEntry> entries)
        {
            return entries.Select(e => GetDeleteEntryType(e)).Aggregate((flags, next) => flags | next);
        }

        /// <summary>
        /// ページ削除用エントリの種類を取得
        /// </summary>
        public static DeleteEntryType GetDeleteEntryType(ArchiveEntry entry)
        {
            if (entry is PlaylistArchiveEntry)
            {
                return DeleteEntryType.PlaylistEntry;
            }
            else if (entry.IsFileSystem)
            {
                return DeleteEntryType.File;
            }
            else
            {
                return DeleteEntryType.ArchiveEntry;
            }
        }
    }
}

﻿using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    /// <summary>
    /// アーカイブエントリをディレクトリを含めて展開する
    /// </summary>
    public abstract class ArchiveExtractor
    {
        private readonly Archive _archive;

        public ArchiveExtractor(Archive archive)
        {
            _archive = archive;
        }

        /// <summary>
        /// エントリをファイルまたはディレクトリにエクスポート
        /// </summary>
        /// <param name="entry"></param>
        /// <param name="exportFileName">エクスポート先のパス</param>
        /// <param name="isOverwrite">上書き許可</param>
        /// <param name="token"></param>
        public virtual async ValueTask ExtractAsync(ArchiveEntry entry, string exportFileName, bool isOverwrite, CancellationToken token)
        {
            Debug.Assert(entry.Archive == _archive);

            // MTAスレッドに限定して実行する
            if (Thread.CurrentThread.GetApartmentState() == ApartmentState.STA)
            {
                await Task.Run(async () => await ExtractAsyncInner(entry, exportFileName, isOverwrite, token));
            }
            else
            {
                await ExtractAsyncInner(entry, exportFileName, isOverwrite, token);
            }
        }

        /// <summary>
        /// エントリをファイルまたはディレクトリにエクスポート (実体)
        /// </summary>
        private async ValueTask ExtractAsyncInner(ArchiveEntry entry, string exportFileName, bool isOverwrite, CancellationToken token)
        {
            NVDebug.AssertMTA();
            Debug.Assert(entry.Archive == _archive);
            Debug.Assert(entry is not null);
            Debug.Assert(!string.IsNullOrEmpty(exportFileName));

            if (_archive.IsDisposed) return;

            if (entry.IsDirectory)
            {
                await ExtractDirectoryEntry(entry, exportFileName, isOverwrite, true, token);
            }
            else
            {
                await ExtractFileEntry(entry, exportFileName, isOverwrite, token);
            }
        }

        /// <summary>
        /// ファイルエントリのエクスポート
        /// </summary>
        private async ValueTask ExtractFileEntry(ArchiveEntry entry, string exportFileName, bool isOverwrite, CancellationToken token)
        {
            if (entry.Id < 0) throw new ArgumentException("Cannot extract this entry: " + entry.EntryName);
            if (entry.IsDirectory) throw new InvalidOperationException("Archive directory: " + entry.EntryName);

            token.ThrowIfCancellationRequested();
            await ExtractEntry(entry, exportFileName, isOverwrite, token);
        }

        /// <summary>
        /// ディレクトリエントリのエクスポート
        /// </summary>
        private async ValueTask ExtractDirectoryEntry(ArchiveEntry entry, string exportFileName, bool isOverwrite, bool decrypt, CancellationToken token)
        {
            if (!entry.IsDirectory) throw new InvalidOperationException("Not archive directory: " + entry.EntryName);

            if (!isOverwrite && Directory.Exists(exportFileName)) throw new IOException($"Directory already exists: {exportFileName}");

            var prefix = CreateEntryPrefix(entry);

            var entries = await CollectEntriesAsync(prefix, decrypt, token);
            if (entries.Count == 0) throw new InvalidOperationException();

            foreach (var child in entries)
            {
                token.ThrowIfCancellationRequested();
                var output = FileIO.CreateUniquePath(LoosePath.Combine(exportFileName, LoosePath.ValidPath(child.EntryName[prefix.Length..])));
                await ExtractEntry(child, output, false, token);
            }
        }

        /// <summary>
        /// エントリのエクスポート
        /// </summary>
        private async ValueTask ExtractEntry(ArchiveEntry entry, string path, bool overwrite, CancellationToken token)
        {
            if (entry.IsDirectory)
            {
                Directory.CreateDirectory(path);
            }
            else
            {
                var outputDir = System.IO.Path.GetDirectoryName(path) ?? throw new IOException($"Illegal path: {path}");
                if (!string.IsNullOrWhiteSpace(outputDir))
                {
                    Directory.CreateDirectory(outputDir);
                }
                await ExtractCore(entry, path, overwrite, token);
            }
        }

        /// <summary>
        /// エントリのファイル展開 コア
        /// </summary>
        /// <param name="entry"></param>
        /// <param name="exportFileName"></param>
        /// <param name="isOverwrite"></param>
        protected abstract ValueTask ExtractCore(ArchiveEntry entry, string exportFileName, bool isOverwrite, CancellationToken token);

        /// <summary>
        /// ディレクトリエントリ以下のエントリ識別用プレフィックスを作成
        /// </summary>
        /// <param name="entry">ディレクトリエントリ</param>
        /// <returns></returns>
        private static string CreateEntryPrefix(ArchiveEntry entry)
        {
            Debug.Assert(entry.IsDirectory);
            return LoosePath.TrimDirectoryEnd(entry.EntryName);
        }

        /// <summary>
        /// ディレクトリエントリ以下のエントリを収集する
        /// </summary>
        /// <param name="entryPrefix"></param>
        /// <param name="token"></param>
        /// <returns></returns>
        public async ValueTask<List<ArchiveEntry>> CollectEntriesAsync(string entryPrefix, bool decrypt, CancellationToken token)
        {
            return (await _archive.GetEntriesAsync(decrypt, token)).Where(e => e.EntryName.StartsWith(entryPrefix, StringComparison.Ordinal)).ToList();
        }
    }
}

