﻿using System;
using System.Collections.Generic;
using System.Linq;

namespace NeeView
{
    /// <summary>
    /// エントリ群のソート
    /// TODO: bookと共通化
    /// </summary>
    public static class EntrySort
    {
        // TODO: 入力された entries を変更しないようにする
        /// <summary>
        /// ソート実行
        /// </summary>
        /// <param name="entries"></param>
        /// <param name="sortMode"></param>
        /// <returns></returns>
        public static List<ArchiveEntry> SortEntries(List<ArchiveEntry> entries, PageSortMode sortMode)
        {
            if (entries is null) throw new();
            if (entries.Count <= 0) return entries;

            switch (sortMode)
            {
                case PageSortMode.FileName:
                    entries.Sort((a, b) => CompareFileNameOrder(a, b, NaturalSort.Comparer));
                    break;
                case PageSortMode.FileNameDescending:
                    entries.Sort((a, b) => CompareFileNameOrder(b, a, NaturalSort.Comparer));
                    break;
                case PageSortMode.FileType:
                    entries.Sort((a, b) => CompareFileTypeOrder(a, b, NaturalSort.Comparer));
                    break;
                case PageSortMode.FileTypeDescending:
                    entries.Sort((a, b) => CompareFileTypeOrder(b, a, NaturalSort.Comparer));
                    break;
                case PageSortMode.TimeStamp:
                    entries.Sort((a, b) => CompareDateTimeOrder(a, b, NaturalSort.Comparer));
                    break;
                case PageSortMode.TimeStampDescending:
                    entries.Sort((a, b) => CompareDateTimeOrder(b, a, NaturalSort.Comparer));
                    break;
                case PageSortMode.Random:
                    var random = new Random();
                    entries = entries.OrderBy(e => random.Next()).ToList();
                    break;
                default:
                    throw new NotImplementedException();
            }

            return entries;
        }

        // ファイル名, 日付, ID の順で比較
        private static int CompareFileNameOrder(ArchiveEntry e1, ArchiveEntry e2, IComparer<string> comparer)
        {
            if (e1.EntryName != e2.EntryName)
                return CompareFileName(e1.EntryName, e2.EntryName, comparer);
            else if (e1.LastWriteTime != e2.LastWriteTime)
                return CompareDateTime(e1.LastWriteTime, e2.LastWriteTime);
            else
                return e1.Id - e2.Id;
        }

        // 種類, ファイル名, ID の順で比較
        private static int CompareFileTypeOrder(ArchiveEntry e1, ArchiveEntry e2, IComparer<string> comparer)
        {
            if (e1.Extension != e2.Extension)
                return CompareFileType(e1.Extension, e2.Extension);
            else if (e1.EntryName != e2.EntryName)
                return CompareFileName(e1.EntryName, e2.EntryName, comparer);
            else
                return e1.Id - e2.Id;
        }

        // 日付, ファイル名, ID の順で比較
        private static int CompareDateTimeOrder(ArchiveEntry e1, ArchiveEntry e2, IComparer<string> comparer)
        {
            if (e1.LastWriteTime != e2.LastWriteTime)
                return CompareDateTime(e1.LastWriteTime, e2.LastWriteTime);
            else if (e1.EntryName != e2.EntryName)
                return CompareFileName(e1.EntryName, e2.EntryName, comparer);
            else
                return e1.Id - e2.Id;
        }

        // ファイル名比較. ディレクトリを優先する
        private static int CompareFileName(string s1, string s2, IComparer<string> comparer)
        {
            string d1 = LoosePath.GetDirectoryName(s1);
            string d2 = LoosePath.GetDirectoryName(s2);

            if (d1 == d2)
                return comparer.Compare(s1, s2);
            else
                return comparer.Compare(d1, d2);
        }

        // 拡張子比較
        private static int CompareFileType(string s1, string s2)
        {
            return string.Compare(s1, s2, StringComparison.Ordinal);
        }

        // 日付比較
        private static int CompareDateTime(DateTime t1, DateTime t2)
        {
            return (t1.Ticks - t2.Ticks < 0) ? -1 : 1;
        }
    }

}

﻿using NeeView.Text;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace NeeView
{
    /// <summary>
    /// ファイル拡張子コレクション
    /// </summary>
    [ObjectMergeReferenceCopy]
    [JsonConverter(typeof(JsonFileTypeCollectionConverter))]
    public class FileTypeCollection : StringCollection, IEquatable<FileTypeCollection>
    {
        public FileTypeCollection()
        {
        }

        public FileTypeCollection(string exts) : base(exts)
        {
        }

        public FileTypeCollection(IEnumerable<string> exts) : base(exts)
        {
        }

        public override string ValidateItem(string item)
        {
            return string.IsNullOrWhiteSpace(item) ? "" : "." + ReplaceInvalidFileNameChars(item).Trim().TrimStart('.').ToLowerInvariant();
        }

        private static string ReplaceInvalidFileNameChars(string s)
        {
            if (s is null) return "";

            var invalidChars = System.IO.Path.GetInvalidFileNameChars();
            return string.Concat(s.Select(c => invalidChars.Contains(c) ? '_' : c));
        }

        public new static FileTypeCollection Parse(string s)
        {
            return new FileTypeCollection(s);
        }

        public bool Equals(FileTypeCollection? other)
        {
            if (other == null) return false;
            return this.ToString() == other.ToString();
        }

        public override bool Equals(object? obj)
        {
            return Equals(obj as FileTypeCollection);
        }

        public override int GetHashCode()
        {
            return this.ToString().GetHashCode(StringComparison.Ordinal);
        }
    }

    public sealed class JsonFileTypeCollectionConverter : JsonConverter<FileTypeCollection>
    {
        public override FileTypeCollection? Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var s = reader.GetString();
            if (s is null) return null;

            return FileTypeCollection.Parse(s);
        }

        public override void Write(Utf8JsonWriter writer, FileTypeCollection value, JsonSerializerOptions options)
        {
            writer.WriteStringValue(value.ToString());
        }
    }
}

﻿//#define LOCAL_DEBUG

using NeeLaboratory.Generators;
using NeeLaboratory.Linq;
using NeeView.IO;
using NeeView.Properties;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    /// <summary>
    /// アーカイバー：通常ファイル
    /// ディレクトリをアーカイブとみなしてアクセスする
    /// </summary>
    [LocalDebug]
    public partial class FolderArchive : Archive
    {
        private FileSystemWatcher? _fileSystemWatcher;

        public FolderArchive(string path, ArchiveEntry? source, ArchiveHint archiveHint) : base(path, source, archiveHint)
        {
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
            }

            TerminateWatcher();

            base.Dispose(disposing);
        }

        public override string ToString()
        {
            return TextResources.GetString("Archiver.Folder");
        }

        // サポート判定
        public override bool IsSupported()
        {
            return true;
        }

        // リスト取得
        protected override async ValueTask<List<ArchiveEntry>> GetEntriesInnerAsync(bool decrypt, CancellationToken token)
        {
            // Pathがない場合は汎用アーカイブなのでリスト作成は行わない
            if (string.IsNullOrEmpty(Path))
            {
                Debug.Fail("If there is no Path, it is a general-purpose archive and does not create a list.");
                return new List<ArchiveEntry>();
            }

            token.ThrowIfCancellationRequested();

            var list = new List<ArchiveEntry>();

            var directory = new DirectoryInfo(Path);
            foreach (var info in directory.EnumerateFileSystemInfos())
            {
                token.ThrowIfCancellationRequested();

                if (!FileIOProfile.Current.IsFileValid(info.Attributes))
                {
                    continue;
                }

                var entry = CreateArchiveEntry(info, list.Count);
                list.Add(entry);
            }

            Debug.Assert(list.All(e => e is FolderArchiveEntry));
            return await Task.FromResult(list);
        }

        protected FolderArchiveEntry CreateArchiveEntry(FileSystemInfo info, int id)
        {
            if (info is DirectoryInfo directoryInfo)
            {
                return CreateArchiveEntry(directoryInfo, id);
            }
            else if (info is FileInfo fileInfo)
            {
                return CreateArchiveEntry(fileInfo, id);
            }
            else
            {
                throw new ArgumentException("not exists entry.", nameof(info));
            }
        }

        protected FolderArchiveEntry CreateArchiveEntry(DirectoryInfo info, int id)
        {
            return CreateCommonArchiveEntry(info, id);
        }

        protected FolderArchiveEntry CreateArchiveEntry(FileInfo info, int id)
        {
            var entry = CreateCommonArchiveEntry(info, id);

            if (FileShortcut.IsShortcut(info.Name))
            {
                var shortcut = new FileShortcut(info);
                if (shortcut.TryGetTarget(out var target))
                {
                    if (target.Attributes.HasFlag(FileAttributes.Directory))
                    {
                        entry.Link = target.FullName;
                        entry.Length = -1;
                        entry.CreationTime = target.GetSafeCreationTime();
                        entry.LastWriteTime = target.GetSafeLastWriteTime();
                    }
                    else
                    {
                        var fileInfo = (FileInfo)target;
                        entry.Link = target.FullName;
                        entry.Length = fileInfo.Length;
                        entry.CreationTime = target.GetSafeCreationTime();
                        entry.LastWriteTime = target.GetSafeLastWriteTime();
                    }
                }
            }

            return entry;
        }

        private FolderArchiveEntry CreateCommonArchiveEntry(FileSystemInfo info, int id)
        {

            var name = string.IsNullOrEmpty(Path) ? info.FullName : info.FullName[Path.Length..].TrimStart('\\', '/');

            var entry = new FolderArchiveEntry(this)
            {
                IsValid = true,
                Id = id,
                RawEntryName = name,
                Length = info is FileInfo fileInfo ? fileInfo.Length : -1,
                CreationTime = info.GetSafeCreationTime(),
                LastWriteTime = info.GetSafeLastWriteTime(),
                HasReparsePoint = info.Attributes.HasFlag(FileAttributes.ReparsePoint)
            };

            return entry;
        }

        public override bool CanRealize(ArchiveEntry entry)
        {
            Debug.Assert(entry.Archive == this);
            return true;
        }

        // ストリームを開く
        protected override async ValueTask<Stream> OpenStreamInnerAsync(ArchiveEntry entry, bool decrypt, CancellationToken token)
        {
            Debug.Assert(entry.Archive == this);
            Debug.Assert(entry.EntityPath is not null);
            return await Task.FromResult(new FileStream(entry.EntityPath, FileMode.Open, FileAccess.Read));
        }

        // ファイル出力
        protected override async ValueTask ExtractToFileInnerAsync(ArchiveEntry entry, string exportFileName, bool isOverwrite, CancellationToken token)
        {
            Debug.Assert(entry.Archive == this);
            Debug.Assert(entry.EntityPath is not null);
            await FileIO.CopyFileAsync(entry.EntityPath, exportFileName, isOverwrite, true, token);
        }

        /// <summary>
        /// exists?
        /// </summary>
        public override bool Exists(ArchiveEntry entry)
        {
            Debug.Assert(entry.Archive == this);
            if (entry.Archive != this) return false;
            if (entry.IsDeleted) return false;

            var path = entry.EntityPath;
            return File.Exists(path) || Directory.Exists(path);
        }

        /// <summary>
        /// can delete
        /// </summary>
        /// <exception cref="ArgumentException">Not registered with this archiver.</exception>
        public override bool CanDelete(List<ArchiveEntry> entries, bool strict)
        {
            if (entries.Any(e => e.Archive != this)) throw new ArgumentException("There are elements not registered with this archiver.", nameof(entries));

            return entries.All(e => e.EntityPath is not null);
        }

        /// <summary>
        /// delete entries
        /// </summary>
        /// <exception cref="ArgumentException">Not registered with this archiver.</exception>
        public override async ValueTask<DeleteResult> DeleteAsync(List<ArchiveEntry> entries)
        {
            if (entries.Any(e => e.Archive != this)) throw new ArgumentException("There are elements not registered with this archiver.", nameof(entries));

            var paths = entries.Select(e => e.EntityPath).WhereNotNull().ToList();
            if (!paths.Any()) return DeleteResult.Success;

            RemoveCachedEntry(entries);
            await FileIO.DeleteAsync(paths);
            return DeleteResult.Success;
        }

        /// <summary>
        /// can rename?
        /// </summary>
        public override bool CanRename(ArchiveEntry entry)
        {
            if (entry.Archive != this) throw new ArgumentException("There are elements not registered with this archiver.", nameof(entry));

            return true;
        }

        /// <summary>
        /// rename
        /// </summary>
        public override async ValueTask<bool> RenameAsync(ArchiveEntry entry, string name)
        {
            if (entry.Archive != this) throw new ArgumentException("There are elements not registered with this archiver.", nameof(entry));

            var src = entry.SystemPath;
            if (src is null) return false;

            // TODO: 名前の補正処理をここで？UI呼ばせるのはよろしくないのでは？
            var dst = FileIO.CreateRenameDst(src, name, true);
            if (dst is null) return false;

            var isSuccess = await FileIO.RenameAsync(src, dst, true);
            if (isSuccess)
            {
                var rawEntryName = System.IO.Path.Combine(System.IO.Path.GetDirectoryName(entry.RawEntryName) ?? "", System.IO.Path.GetFileName(dst));
                entry.RawEntryName = rawEntryName;
            }

            return isSuccess;
        }

        #region FileSystemWatcher

        protected override void OnStartWatch()
        {
            InitializeWatcher(Path);
        }

        protected override void OnStopWatch()
        {
            TerminateWatcher();
        }

        /// <summary>
        /// ファイルシステム監視初期化
        /// </summary>
        /// <param name="path"></param>
        private void InitializeWatcher(string path)
        {
            if (_fileSystemWatcher != null)
            {
                Debug.Assert(_fileSystemWatcher.Path == path);
                return;
            }

            _fileSystemWatcher = new FileSystemWatcher();

            try
            {
                LocalDebug.WriteLine($"Path={path}");
                _fileSystemWatcher.Path = path;
                _fileSystemWatcher.IncludeSubdirectories = false;
                _fileSystemWatcher.NotifyFilter = NotifyFilters.FileName | NotifyFilters.DirectoryName;
                _fileSystemWatcher.Created += Watcher_Created;
                _fileSystemWatcher.Deleted += Watcher_Deleted;
                _fileSystemWatcher.Renamed += Watcher_Renamed;
                _fileSystemWatcher.Error += Watcher_Error;
                _fileSystemWatcher.EnableRaisingEvents = true;
            }
            catch (Exception e)
            {
                Debug.WriteLine(e.Message);
                _fileSystemWatcher.Dispose();
                _fileSystemWatcher = null;
            }
        }

        /// <summary>
        /// ファイルシステム監視終了
        /// </summary>
        private void TerminateWatcher()
        {
            if (_fileSystemWatcher != null)
            {
                LocalDebug.WriteLine($"Path={_fileSystemWatcher.Path}");
                _fileSystemWatcher.EnableRaisingEvents = false;
                _fileSystemWatcher.Error -= Watcher_Error;
                _fileSystemWatcher.Created -= Watcher_Created;
                _fileSystemWatcher.Deleted -= Watcher_Deleted;
                _fileSystemWatcher.Renamed -= Watcher_Renamed;
                _fileSystemWatcher.Dispose();
                _fileSystemWatcher = null;
            }
        }

        private void Watcher_Error(object sender, ErrorEventArgs e)
        {
            var ex = e.GetException();
            LocalDebug.WriteLine($"Error!! : {ex} : {ex.Message}");

            // recovery...
            ////var path = _fileSystemWatcher.Path;
            ////TerminateWatcher();
            ////InitializeWatcher(path);
        }

        private void Watcher_Created(object sender, FileSystemEventArgs e)
        {
            LocalDebug.WriteLine($"{e.FullPath}");

            AppDispatcher.BeginInvoke(() =>
            {
                OnCreated(e);
            });
        }

        private void Watcher_Deleted(object sender, FileSystemEventArgs e)
        {
            if (e.Name is null) return;
            LocalDebug.WriteLine($"{e.FullPath}");

            AppDispatcher.BeginInvoke(() =>
            {
                RemoveCachedEntry(e.Name);
                OnDeleted(e);
            });
        }

        private void RemoveCachedEntry(string entryName)
        {
            var entries = GetEntriesCache();
            if (entries is null) return;

            var entry = entries.FirstOrDefault(e => e.RawEntryName == entryName);
            if (entry is null) return;

            RemoveCachedEntry(entry);
        }

        private void Watcher_Renamed(object sender, RenamedEventArgs e)
        {
            LocalDebug.WriteLine($"{e.OldFullPath} => {e.Name}");

            AppDispatcher.BeginInvoke(() =>
            {
                OnRenamed(e);
            });
        }

        #endregion FileSystemWatcher
    }

}

