﻿using NeeLaboratory.Threading;
using SevenZip;
using System;
using System.Collections.Generic;
using System.Collections.ObjectModel;
using System.Diagnostics;
using System.IO;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{

    /// <summary>
    /// SevenZipSharpのインスタンスアクセサ。
    /// 一時的にファイルロックを解除できるようにしている。
    /// </summary>
    public class SevenZipAccessor : IDisposable
    {
        private static bool _isLibraryInitialized;

        // NOTE: 複数のアーカイブに同時にアクセスすると処理が極端に落ち込むようなので、並列アクセスを制限してみる
        private static readonly AsyncLock _asyncLock = new();

        public static void InitializeLibrary()
        {
            if (_isLibraryInitialized) return;

            string dllPath = Environment.IsX64 ? Config.Current.Archive.SevenZip.X64DllPath : Config.Current.Archive.SevenZip.X86DllPath;
            if (string.IsNullOrWhiteSpace(dllPath))
            {
                dllPath = System.IO.Path.Combine(Environment.LibrariesPlatformPath, "7z.dll");
            }

            SevenZipExtractor.SetLibraryPath(dllPath);

            FileVersionInfo dllVersionInfo = FileVersionInfo.GetVersionInfo(dllPath);
            Debug.WriteLine("7z.dll: ver" + dllVersionInfo?.FileVersion);

            _isLibraryInitialized = true;
        }


        private readonly string _fileName;
        private SevenZipExtractor? _extractor;
        private readonly Lock _lock = new();
        private readonly ArchiveKey _archiveKey;


        public SevenZipAccessor(string fileName)
        {
            InitializeLibrary();
            _fileName = fileName;

            _archiveKey = new ArchiveKey(fileName);
            _archiveKey.KeyChanged += (s, e) => UnlockCore();
        }


        public string Format
        {
            get
            {
                using (_asyncLock.Lock())
                {
                    if (_disposedValue) return "";
                    return GetExtractor().Format.ToString();
                }
            }
        }

        public bool IsSolid
        {
            get
            {
                using (_asyncLock.Lock())
                {
                    if (_disposedValue) return false;
                    return GetExtractor().IsSolid;
                }
            }
        }


        public ReadOnlyCollection<ArchiveFileInfo> ArchiveFileData
        {
            get
            {
                using (_asyncLock.Lock())
                {
                    if (_disposedValue) return new List<ArchiveFileInfo>().AsReadOnly();
                    // TODO: 重い処理。キャンセルできるようにしたい
                    return GetExtractor().ArchiveFileData;
                }
            }
        }


        /// <summary>
        /// エクストラクタの取得
        /// </summary>
        private SevenZipExtractor GetExtractor()
        {
            lock (_lock)
            {
                ThrowIfDisposed();

                if (_extractor is null)
                {
                    if (string.IsNullOrEmpty(_archiveKey.Key))
                    {
                        _extractor = new SevenZipExtractor(_fileName);
                    }
                    else
                    {
                        _extractor = new SevenZipExtractor(_fileName, _archiveKey.Key);
                    }
                }

                return _extractor;
            }
        }

        /// <summary>
        /// エクストラクタを開放し、ファイルをアンロックする
        /// </summary>
        public void Unlock()
        {
            using (_asyncLock.Lock())
            {
                UnlockCore();
            }
        }

        private void UnlockCore()
        {
            if (_disposedValue) return;
            lock (_lock)
            {
                _extractor?.Dispose();
                _extractor = null;
            }
        }

        /// <summary>
        /// アーカイブ情報をまとめて取得
        /// </summary>
        /// <returns></returns>
        public (SevenZipArchiveInfo Info, ReadOnlyCollection<ArchiveFileInfo> Entries) GetArchiveInfo(bool decrypt)
        {
            using (_asyncLock.Lock())
            {
                if (_disposedValue) return new();
                SevenZipExtractor? extractor = null;

                while (true)
                {
                    try
                    {
                        extractor = GetExtractor();
                        return new(new SevenZipArchiveInfo(extractor.Format.ToString(), extractor.IsSolid, extractor.PasswordRequired), extractor.ArchiveFileData);
                    }
                    catch (SevenZipArchiveException) when (decrypt)
                    {
                        if (extractor is not null && extractor.PasswordRequired)
                        {
                            if (_archiveKey.UpdateArchiveKeyByUser())
                            {
                                continue;
                            }
                        }

                        throw;
                    }
                }
            }
        }

        /// <summary>
        /// アーカイブエントリを出力する
        /// </summary>
        /// <param name="index">エントリ番号</param>
        /// <param name="extractStream">出力ストリーム</param>
        /// <param name="decrypt">暗号解除</param>
        public void ExtractFile(SevenZipFileInfo info, Stream extractStream, bool decrypt)
        {
            using (_asyncLock.Lock())
            {
                if (_disposedValue) return;

                while (true)
                {
                    try
                    {
                        GetExtractor().ExtractFile(info.Index, extractStream);
                        break;
                    }
                    catch (ExtractionFailedException ex) when (decrypt && (ex.OperationResult == OperationResult.DataError || ex.OperationResult == OperationResult.WrongPassword))
                    {
                        if (!info.Encrypted)
                        {
                            throw;
                        }

                        if (_archiveKey.UpdateArchiveKeyByUser())
                        {
                            continue;
                        }

                        throw;
                    }
                }
            }
        }

        /// <summary>
        /// すべてのアーカイブエントリを出力する
        /// </summary>
        /// <remarks>
        /// ソリッドアーカイブ用。
        /// すべてのエントリを連続処理し、コールバックで各エントリの出力を制御する。
        /// </remarks>
        /// <param name="directory">ファイルの出力フォルダー</param>
        /// <param name="fileExtraction">エントリの出力定義</param>
        /// <param name="token"></param>
        /// <returns></returns>
        public async ValueTask PreExtractAsync(bool encryptedMaybe, string directory, SevenZipFileExtraction fileExtraction, bool decrypt, CancellationToken token)
        {
            Debug.Assert(!string.IsNullOrEmpty(directory));

            using (await _asyncLock.LockAsync(token))
            {
                if (_disposedValue) return;

                while (true)
                {
                    try
                    {
                        var preExtractor = new SevenZipHybridExtractor(GetExtractor(), directory, fileExtraction);
                        await preExtractor.ExtractAsync(token);
                        break;
                    }
                    catch (ExtractionFailedException ex) when (decrypt && (ex.OperationResult == OperationResult.DataError || ex.OperationResult == OperationResult.WrongPassword))
                    {
                        if (!encryptedMaybe)
                        {
                            throw;
                        }

                        if (_archiveKey.UpdateArchiveKeyByUser())
                        {
                            continue;
                        }

                        throw;
                    }
                }
            }
        }


        #region IDisposable Support
        private bool _disposedValue = false;

        protected void ThrowIfDisposed()
        {
            if (_disposedValue) throw new ObjectDisposedException(GetType().FullName);
        }

        protected virtual void Dispose(bool disposing)
        {
            lock (_lock)
            {
                if (!_disposedValue)
                {
                    if (disposing)
                    {
                    }

                    // NOTE: ファイルロックを解除する
                    _extractor?.Dispose();
                    _extractor = null;

                    _disposedValue = true;
                }
            }
        }

        ~SevenZipAccessor()
        {
            Dispose(disposing: false);
        }

        public void Dispose()
        {
            Dispose(true);
            GC.SuppressFinalize(this);
        }
        #endregion
    }


    public readonly record struct SevenZipArchiveInfo(string? Format, bool IsSolid, bool Encrypted);

    public readonly record struct SevenZipFileInfo(int Index, bool Encrypted);

    public static partial class ArchiveEntryExtensions
    {
        public static SevenZipFileInfo ToSevenZipFileInfo(this ArchiveEntry entry)
        {
            return new SevenZipFileInfo(entry.Id, entry.Encrypted);
        }
    }
}

﻿using NeeView.Properties;
using SevenZip;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    /// <summary>
    /// アーカイバー：7z.dll
    /// </summary>
    public class SevenZipArchive : Archive
    {
        private readonly SevenZipAccessor _accessor;
        private SevenZipArchiveInfo _archiveInfo;

        public SevenZipArchive(string path, ArchiveEntry? source, ArchiveHint archiveHint) : base(path, source, archiveHint)
        {
            _accessor = new SevenZipAccessor(Path);
        }


        public bool IsSolid => _archiveInfo.IsSolid;

        public string? Format => _archiveInfo.Format;


        public override string ToString()
        {
            return TextResources.GetString("Archiver.SevenZip") + (Format != null ? $" ({Format})" : null);
        }

        public override void Unlock()
        {
            // 直接の圧縮ファイルである場合のみアンロック
            if (this.Parent == null || this.Parent is FolderArchive)
            {
                NVDebug.AssertMTA();
                _accessor.Unlock();
            }
        }


        // サポート判定
        public override bool IsSupported()
        {
            return true;
        }

        // [開発用] 初期化済？
        public bool Initialized() => Format != null;

        // エントリーリストを得る
        protected override async ValueTask<List<ArchiveEntry>> GetEntriesInnerAsync(bool decrypt, CancellationToken token)
        {
            NVDebug.AssertMTA();
            token.ThrowIfCancellationRequested();

            if (_disposedValue) return new List<ArchiveEntry>();

            var list = new List<ArchiveEntry>();
            var directories = new List<ArchiveEntry>();

            // NOTE: 最初のアーカイブ初期化に時間がかかることがあるが、外部DLL内なのでキャンセルできない。
            // NOTE: アーカイブの種類によっては進捗が取得できるようだ。
            (_archiveInfo, var entries) = _accessor.GetArchiveInfo(decrypt);

            Encrypted = _archiveInfo.Encrypted || entries.Any(e => e.Encrypted);

            for (int id = 0; id < entries.Count; ++id)
            {
                token.ThrowIfCancellationRequested();

                var entry = entries[id];
                Debug.Assert(entry.Index == id);

                var archiveEntry = new ArchiveEntry(this)
                {
                    IsValid = true,
                    Id = id,
                    RawEntryName = entry.FileName,
                    Length = (long)entry.Size,
                    CreationTime = entry.CreationTime,
                    LastWriteTime = entry.LastWriteTime,
                    Encrypted = entry.Encrypted,
                };

                if (!entry.IsDirectory)
                {
                    list.Add(archiveEntry);
                }
                else
                {
                    archiveEntry.Length = -1;
                    directories.Add(archiveEntry);
                }
            }

            // ディレクトリエントリを追加
            list.AddRange(CreateDirectoryEntries(list.Concat(directories)));

            await ReadZoneIdentifierAsync(token);

            return list;
        }

        // エントリーのストリームを得る
        protected override async ValueTask<Stream> OpenStreamInnerAsync(ArchiveEntry entry, bool decrypt, CancellationToken token)
        {
            NVDebug.AssertMTA();
            Debug.Assert(entry is not null);
            Debug.Assert(Initialized());
            Debug.Assert(!CanPreExtract(), "Pre-extract, so no direct extract.");
            if (entry.Id < 0) throw new ArgumentException("Cannot open this entry: " + entry.EntryName);

            ThrowIfDisposed();

#if DEBUG
            var archiveEntry = _accessor.ArchiveFileData[entry.Id];
            if (archiveEntry.FileName != entry.RawEntryName)
            {
                throw new ApplicationException(TextResources.GetString("InconsistencyException.Message"));
            }
#endif

            var ms = new MemoryStream((int)entry.Length);
            token.ThrowIfCancellationRequested();
            await Task.Run(() => _accessor.ExtractFile(entry.ToSevenZipFileInfo(), ms, decrypt));
            ms.Seek(0, SeekOrigin.Begin);
            return ms;
        }

        /// <summary>
        /// 実体化可能なエントリ？
        /// </summary>
        public override bool CanRealize(ArchiveEntry entry)
        {
            Debug.Assert(entry.Archive == this);
            return true;
        }

        /// <summary>
        /// エントリをファイルまたはディレクトリにエクスポート
        /// </summary>
        /// <param name="entry"></param>
        /// <param name="exportFileName">エクスポート先のパス</param>
        /// <param name="isOverwrite">上書き許可</param>
        /// <param name="token"></param>
        protected override async ValueTask ExtractToFileInnerAsync(ArchiveEntry entry, string exportFileName, bool isOverwrite, CancellationToken token)
        {
            Debug.Assert(entry.Archive == this);
            var extractor = new SevenZipArchiveExtractor(this);
            await extractor.ExtractAsync(entry, exportFileName, isOverwrite, token);
        }

        public void Extract(ArchiveEntry entry, string exportFileName, bool isOverwrite, CancellationToken token)
        {
            NVDebug.AssertMTA();
            Debug.Assert(entry.Archive == this);
            if (entry.Id < 0) throw new ApplicationException("Cannot open this entry: " + entry.EntryName);
            if (entry.IsDirectory) throw new ApplicationException("This entry is directory: " + entry.EntryName);

            var mode = isOverwrite ? FileMode.Create : FileMode.CreateNew;
            using (Stream fs = new FileStream(exportFileName, mode, FileAccess.Write))
            {
                _accessor.ExtractFile(entry.ToSevenZipFileInfo(), fs, true);
            }
            WriteZoneIdentifier(exportFileName);
        }

        /// <summary>
        /// 事前展開？
        /// </summary>
        protected override bool CanPreExtractInner()
        {
            if (_disposedValue) return false;
            Debug.Assert(Initialized());
            return IsSolid;
        }

        /// <summary>
        /// 事前展開処理
        /// </summary>
        public override async ValueTask PreExtractAsync(string directory, bool decrypt, CancellationToken token)
        {
            Debug.Assert(!string.IsNullOrEmpty(directory));

            if (_disposedValue) return;

            var entries = await GetEntriesAsync(decrypt, token);
            token.ThrowIfCancellationRequested();

            await _accessor.PreExtractAsync(Encrypted, directory, new SevenZipFileExtraction(entries), decrypt, token);
            token.ThrowIfCancellationRequested();
        }


        #region IDisposable Support
        private bool _disposedValue = false;

        protected void ThrowIfDisposed()
        {
            if (_disposedValue) throw new ObjectDisposedException(GetType().FullName);
        }

        protected override void Dispose(bool disposing)
        {
            if (!_disposedValue)
            {
                if (disposing)
                {
                }
                _accessor?.Dispose();
                _disposedValue = true;
                base.Dispose(disposing);
            }
        }
        #endregion
    }


    /// <summary>
    /// ストリーム展開時のエントリアクセサ
    /// </summary>
    public class SevenZipFileExtraction : ISevenZipFileExtraction
    {
        private readonly Dictionary<int, ArchiveEntry> _map;

        public SevenZipFileExtraction(List<ArchiveEntry> entries)
        {
            _map = entries.Where(e => e.Id >= 0).ToDictionary(e => e.Id);
        }

        public bool DataExists(ArchiveFileInfo info)
        {
            if (_map.TryGetValue(info.Index, out var entry))
            {
                return entry.Data is not null;
            }
            return true;
        }

        public void SetData(ArchiveFileInfo info, object data)
        {
            if (_map.TryGetValue(info.Index, out var entry))
            {
                entry.SetData(data);
            }
            else
            {
                Debug.Assert(false, "Don't come here: Entry not found");
            }
        }

        public void WriteZoneIdentifier(ArchiveFileInfo info)
        {
            if (_map.TryGetValue(info.Index, out var entry) && entry.Data is string path)
            {
                entry.Archive.WriteZoneIdentifier(path);
            }
        }
    }
}

