using NeeLaboratory.Generators;
using NeeLaboratory.Threading;
using System;
using System.Collections.Generic;
using System.IO;
using System.IO.Compression;
using System.Text;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    [LocalDebug]
    public partial class ZipArchiveWriter
    {
        private readonly ZipArchiveWriterManager _manager;
        private readonly string _path;
        private readonly Encoding? _encoding;
        private readonly List<ZipArchiveEntryIdent> _idents = new();
        private readonly System.Threading.Lock _lock;
        private Task? _task;
        private CancellationTokenSource _tokenSource = new();


        public ZipArchiveWriter(ZipArchiveWriterManager manager, string path, Encoding? encoding = null)
        {
            _manager = manager;
            _lock = _manager.GetLockObject();
            _path = path;
            _encoding = encoding;
        }


        public void Cancel()
        {
            _tokenSource.Cancel();
            _tokenSource = new CancellationTokenSource();
        }

        public bool Contains(ZipArchiveEntryIdent ident)
        {
            lock (_lock)
            {
                return _idents.Contains(ident);
            }
        }

        public Task? CreateDeleteTask(IEnumerable<ZipArchiveEntryIdent> idents, AsyncLock asyncLock)
        {
            lock (_lock)
            {
                foreach (var ident in idents)
                {
                    LocalDebug.WriteLine($"Add: {ident.FullName}");
                }

                _idents.AddRange(idents);
                if (_task is null)
                {
                    _task = Task.Run(async () => await DeleteAsync(asyncLock, _tokenSource.Token));
                    return _task;
                }
            }

            return null;
        }

        private async ValueTask DeleteAsync(AsyncLock asyncLock, CancellationToken token)
        {
            LocalDebug.WriteLine($"Start task: {_path}");

            var tempFilename = FileIO.CreateUniquePath(_path + ".temp");

            using var scope = WorkingProgressWatcher.Current.Lock($"{LoosePath.GetFileName(_path)}...", () => _tokenSource.Cancel());

            try
            {
                using var processLock = MainViewComponent.Current.LockProcessing();
                var index = 0;

                while (true)
                {
                    LocalDebug.WriteLine($"Copy to temp file: {_path}");

                    token.ThrowIfCancellationRequested();
                    await CopyAsync(_path, tempFilename, token);

                    while (true)
                    {
                        LocalDebug.WriteLine($"Open archive: {_path}");

                        token.ThrowIfCancellationRequested();
                        using (var archive = ZipFile.Open(tempFilename, ZipArchiveMode.Update, _encoding))
                        {
                            while (true)
                            {
                                ZipArchiveEntryIdent ident;
                                lock (_lock)
                                {
                                    if (_idents.Count <= index) break;
                                    ident = _idents[index++];
                                }
                                token.ThrowIfCancellationRequested();
                                var entry = archive.FindEntry(ident);
                                if (entry is null)
                                {
                                    LocalDebug.WriteLine($"Cannot found {ident.FullName}");
                                }
                                else
                                {
                                    LocalDebug.WriteLine($"Delete entry: {entry.FullName}");
                                    entry.Delete();
                                }
                            }
                        }

                        lock (_lock)
                        {
                            if (_idents.Count <= index) break;
                        }
                    }

                    token.ThrowIfCancellationRequested();
                    LocalDebug.WriteLine($"Replace file: {_path}");

                    // 元のファイルへ差し替え。
                    // 元ファイルアクセス中は置き換えできないのでリトライさせる
                    int retryCount = 0;
                    while (true)
                    {
                        try
                        {
                            using (await asyncLock.LockAsync(token))
                            {
                                FileIO.Replace(tempFilename, _path, null);
                            }
                            break;
                        }
                        catch
                        {
                            retryCount++;
                            if (retryCount >= 5) throw;
                            LocalDebug.WriteLine($"Retry: {_path}");
                            await Task.Delay(1000, token);
                        }
                    }

                    lock (_lock)
                    {
                        if (_idents.Count <= index)
                        {
                            _manager.DetachArchive(_path);
                            break;
                        }
                    }

                    LocalDebug.WriteLine($"Done: {_path}");
                }
            }
            catch (Exception ex)
            {
                LocalDebug.WriteLine($"Exception: {ex.Message}");

                if (File.Exists(tempFilename))
                {
                    File.Delete(tempFilename);
                }
                _manager.DetachArchive(_path);

                throw;
            }
        }

        private static async ValueTask CopyAsync(string src, string dst, CancellationToken token)
        {
            using var sourceStream = File.Open(src, FileMode.Open, FileAccess.Read, FileShare.Read);
            using var destinationStream = File.Create(dst);
            await sourceStream.CopyToAsync(destinationStream, token);
            await destinationStream.FlushAsync(token);
        }

    }
}

﻿using System;
using System.Diagnostics;
using System.IO;
using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    /// <summary>
    /// Zone.Identifier をコピーするためのもの。生成はしない。
    /// </summary>
    public class ZoneIdentifier
    {
        private readonly byte[] _bytes;

        private ZoneIdentifier(byte[] bytes)
        {
            _bytes = bytes;
        }

        public static ZoneIdentifier? Read(string path)
        {
            try
            {
                var zoneIdentifierPath = GetZoneIdentifierPath(path);
                if (File.Exists(zoneIdentifierPath))
                {
                    var bytes = File.ReadAllBytes(zoneIdentifierPath);
                    return new ZoneIdentifier(bytes);
                }
            }
            catch (Exception ex)
            {
                Debug.WriteLine(ex.Message);
            }

            return null;
        }

        public static async ValueTask<ZoneIdentifier?> ReadAsync(string path, CancellationToken token)
        {
            try
            {
                var zoneIdentifierPath = GetZoneIdentifierPath(path);
                if (File.Exists(zoneIdentifierPath))
                {
                    var bytes = await File.ReadAllBytesAsync(zoneIdentifierPath, token);
                    return new ZoneIdentifier(bytes);
                }
            }
            catch (Exception ex)
            {
                Debug.WriteLine(ex.Message);
            }

            return null;
        }

        public void Write(string path)
        {
            if (_bytes is null) return;

            try
            {
                var zoneIdentifierPath = GetZoneIdentifierPath(path);
                File.WriteAllBytes(zoneIdentifierPath, _bytes);
            }
            catch (Exception ex)
            {
                Debug.WriteLine(ex.Message);
            }
        }

        public async ValueTask WriteAsync(string path, CancellationToken token)
        {
            if (_bytes is null) return;

            try
            {
                var zoneIdentifierPath = GetZoneIdentifierPath(path);
                await File.WriteAllBytesAsync(zoneIdentifierPath, _bytes, token);
            }
            catch (Exception ex)
            {
                Debug.WriteLine(ex.Message);
            }
        }

        private static string GetZoneIdentifierPath(string path)
        {
            return path + ":Zone.Identifier";
        }
    }
}

﻿using NeeView.Media.Imaging.Metadata;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO;
using System.Windows;
using System.Windows.Media;
using System.Windows.Media.Imaging;

namespace NeeView
{
    /// <summary>
    /// Bitmap 情報
    /// </summary>
    public class BitmapInfo
    {
        private readonly static List<BitmapInfoFactory> _bitmapInfoFactories = new List<BitmapInfoFactory>()
        {
            new WebPBitmapInfoFactory(),
            new DefaultBitmapInfoFactory(),
        };


        public BitmapInfo()
        {
            this.Metadata = BitmapMetadataDatabase.Default;
        }

        public BitmapInfo(BitmapFrame bitmapFrame, Stream stream)
        {
            this.PixelWidth = bitmapFrame.PixelWidth;
            this.PixelHeight = bitmapFrame.PixelHeight;
            this.PixelFormat = bitmapFrame.Format;
            this.BitsPerPixel = bitmapFrame.Format.BitsPerPixel;
            this.FrameCount = bitmapFrame.Decoder is GifBitmapDecoder gifBitmapDecoder ? gifBitmapDecoder.Frames.Count : 1;
            this.DpiX = bitmapFrame.DpiX;
            this.DpiY = bitmapFrame.DpiY;
            this.AspectWidth = bitmapFrame.Width;
            this.AspectHeight = bitmapFrame.Height;
            this.Metadata = CreateMetadataDatabase(bitmapFrame, stream);
            this.HasAlpha = bitmapFrame.HasAlpha();

            ////Debug.WriteLine($"Meta.Format: {this.Metadata.Format}");

            SetOrientation(this.Metadata);
        }

        public BitmapInfo(WebPImageInfo info, Stream stream)
        {
            this.PixelWidth = info.PixelWidth;
            this.PixelHeight = info.PixelHeight;
            this.PixelFormat = info.Format;
            this.BitsPerPixel = info.BitsPerPixel;
            this.FrameCount = info.FrameCount;
            this.DpiX = info.DpiX;
            this.DpiY = info.DpiY;
            this.AspectWidth = info.Width;
            this.AspectHeight = info.Height;
            this.Metadata = CreateMetadataDatabase(stream);
            this.HasAlpha = info.HasAlpha;

            SetOrientation(this.Metadata);
            SetResolution(this.Metadata);
        }


        public int PixelWidth { get; private set; }
        public int PixelHeight { get; private set; }
        public PixelFormat PixelFormat { get; private set; }
        public int BitsPerPixel { get; private set; }
        public bool IsMirrorHorizontal { get; private set; }
        public bool IsMirrorVertical { get; private set; }
        public Rotation Rotation { get; private set; }
        public double DpiX { get; private set; }
        public double DpiY { get; private set; }
        public double AspectWidth { get; private set; }
        public double AspectHeight { get; private set; }
        public int FrameCount { get; private set; }
        public BitmapMetadataDatabase Metadata { get; private set; }
        public bool IsTranspose => (this.Rotation == Rotation.Rotate90 || this.Rotation == Rotation.Rotate270);
        public bool? HasAlpha { get; private set; }


        private void SetOrientation(BitmapMetadataDatabase metadata)
        {
            if (metadata.IsValid && metadata.IsOrientationEnabled && metadata[BitmapMetadataKey.Orientation] is ExifOrientation orientation)
            {
                switch (orientation)
                {
                    default:
                    case ExifOrientation.Normal:
                        break;
                    case ExifOrientation.MirrorHorizontal:
                        this.IsMirrorHorizontal = true;
                        break;
                    case ExifOrientation.Rotate180:
                        this.Rotation = Rotation.Rotate180;
                        break;
                    case ExifOrientation.MirrorVertical:
                        this.IsMirrorVertical = true;
                        break;
                    case ExifOrientation.MirrorHorizontal_Rotate270:
                        this.IsMirrorHorizontal = true;
                        this.Rotation = Rotation.Rotate270;
                        break;
                    case ExifOrientation.Rotate90:
                        this.Rotation = Rotation.Rotate90;
                        break;
                    case ExifOrientation.MirrorHorizontal_Rotate90:
                        this.IsMirrorHorizontal = true;
                        this.Rotation = Rotation.Rotate90;
                        break;
                    case ExifOrientation.Rotate270:
                        this.Rotation = Rotation.Rotate270;
                        break;
                }
            }
        }

        private void SetResolution(BitmapMetadataDatabase metadata)
        {
            if (metadata.IsValid)
            {
                if (metadata[BitmapMetadataKey.XResolution] is double dpiX && dpiX > 0.0)
                {
                    this.DpiX = dpiX;
                    this.AspectWidth = this.PixelWidth * (96.0 / this.DpiX);
                }
                if (metadata[BitmapMetadataKey.YResolution] is double dpiY && dpiY > 0.0)
                {
                    this.DpiY = dpiY;
                    this.AspectHeight = this.PixelHeight * (96.0 / this.DpiY);
                }
            }
        }

        private static BitmapMetadataDatabase CreateMetadataDatabase(BitmapFrame bitmapFrame, Stream stream)
        {
            try
            {
                var database = new BitmapMetadataDatabase(GetBitmapMetadata(bitmapFrame));
                if (database.IsValid)
                {
                    return database;
                }
            }
            catch
            {
            }

            return CreateMetadataDatabase(stream);
        }

        private static BitmapMetadataDatabase CreateMetadataDatabase(Stream stream)
        {
            BitmapMetadataDatabase database;

            var pos = stream.Position;
            stream.Seek(0, SeekOrigin.Begin);
            try
            {
                database = new BitmapMetadataDatabase(stream);
            }
            catch
            {
                database = new BitmapMetadataDatabase();
            }
            finally
            {
                stream.Seek(pos, SeekOrigin.Begin);
            }

            return database;
        }

        private static BitmapMetadata? GetBitmapMetadata(BitmapFrame bitmapFrame)
        {
            if (bitmapFrame.Decoder is GifBitmapDecoder decoder)
            {
                try
                {
                    return decoder.Metadata ?? (bitmapFrame.Metadata as BitmapMetadata);
                }
                catch
                {
                    // nop.
                }
            }

            return bitmapFrame.Metadata as BitmapMetadata;
        }

        public Size GetPixelSize()
        {
            return (this.PixelWidth == 0.0 || this.PixelHeight == 0.0) ? Size.Empty : new Size(this.PixelWidth, this.PixelHeight);
        }

        public Size GetAspectSize()
        {
            return (this.AspectWidth == 0.0 || this.AspectHeight == 0.0) ? Size.Empty : new Size(this.AspectWidth, this.AspectHeight);
        }

        public static BitmapInfo Create(Stream stream)
        {
            return Create(stream, false);
        }

        public static BitmapInfo Create(Stream stream, bool throwException)
        {
            stream.Seek(0, SeekOrigin.Begin);

            try
            {
                foreach (var factory in _bitmapInfoFactories)
                {
                    if (factory.CheckFormat(stream))
                    {
                        stream.Seek(0, SeekOrigin.Begin);
                        return factory.Create(stream);
                    }
                }
                throw new InvalidOperationException("Don't come here");
            }
            catch (Exception ex)
            {
                if (throwException)
                {
                    throw;
                }
                else
                {
                    Debug.WriteLine(ex.Message);
                    return new BitmapInfo();
                }
            }
        }


        #region 開発用

        [Conditional("DEBUG")]
        private void DumpMetaData(string prefix, BitmapMetadata metadata)
        {
            foreach (var name in metadata)
            {
                string query;

                try
                {
                    query = prefix + "(" + metadata.Format + ")" + name;
                }
                catch
                {
                    query = prefix + name;
                }

                if (metadata.ContainsQuery(name))
                {
                    var element = metadata.GetQuery(name);
                    if (element is BitmapMetadata bitmapMetadata)
                    {
                        DumpMetaData(query, bitmapMetadata);
                    }
                    else
                    {
                        Debug.WriteLine($"{query}: {element?.ToString()}");
                    }
                }
                else
                {
                    Debug.WriteLine($"{prefix}: {name}");
                }
            }
        }

        #endregion

    }
}

﻿using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;
using System.Windows.Media;
using System.Windows.Media.Imaging;

namespace NeeView
{
    public static class BitmapSourceExtension
    {
        private static readonly string _defaultFormatLabel = PixelFormats.Default.ToString();

        // from http://www.nminoru.jp/~nminoru/programming/bitcount.html
        public static int BitCount(int bits)
        {
            bits = (bits & 0x55555555) + (bits >> 1 & 0x55555555);
            bits = (bits & 0x33333333) + (bits >> 2 & 0x33333333);
            bits = (bits & 0x0f0f0f0f) + (bits >> 4 & 0x0f0f0f0f);
            bits = (bits & 0x00ff00ff) + (bits >> 8 & 0x00ff00ff);
            return (bits & 0x0000ffff) + (bits >> 16 & 0x0000ffff);
        }

        // from http://www.nminoru.jp/~nminoru/programming/bitcount.html
        public static int BitNTZ(int bits)
        {
            return BitCount((~bits) & (bits - 1));
        }

        // GetOneColor()のサポートフォーマット
        private static readonly PixelFormat[] _supportedFormats = new PixelFormat[]
        {
            PixelFormats.Bgra32,
            PixelFormats.Bgr32,
            PixelFormats.Bgr24,
            PixelFormats.Bgr555,
            PixelFormats.Bgr565,
            PixelFormats.Gray8,
            PixelFormats.Gray4,
            PixelFormats.Gray2,
        };

        // GetOneColor()のサポートフォーマット (インデックスカラー)
        private static readonly PixelFormat[] _supportedIndexFormats = new PixelFormat[]
        {
            PixelFormats.Indexed8,
            PixelFormats.Indexed4,
            PixelFormats.Indexed2,
            PixelFormats.Indexed1,
        };

        private static readonly PixelFormat[] _supportedAlphaFormats = new PixelFormat[]
        {
            PixelFormats.Prgba64,
            PixelFormats.Prgba128Float,
            PixelFormats.Pbgra32,
            PixelFormats.Bgra32,
            PixelFormats.Rgba128Float,
            PixelFormats.Rgba64,
        };


        /// <summary>
        /// 有効BitsPerPixelを取得する
        /// </summary>
        /// <param name="bitmap"></param>
        /// <returns></returns>
        public static int GetSourceBitsPerPixel(this BitmapSource bitmap)
        {
            if (bitmap == null) return 0;
            return bitmap.Format.BitsPerPixel;
        }


        /// <summary>
        /// 画像の最初の1ピクセルのカラーを取得
        /// </summary>
        /// <param name="bitmap"></param>
        /// <returns></returns>
        public static Color GetOneColor(this BitmapSource bitmap)
        {
            if (bitmap == null) return Colors.Black;

            // 1pixel取得
            var pixels = new int[1];
            bitmap.CopyPixels(new System.Windows.Int32Rect(0, 0, 1, 1), pixels, 4, 0);

            // ビットマスクを適用して要素の値を取得する
            var elements = new List<byte>();
            foreach (PixelFormatChannelMask channelMask in bitmap.Format.Masks)
            {
                int bits = 0;
                int index = 0;

                foreach (byte myByte in channelMask.Mask)
                {
                    bits |= (myByte << (index++ * 8));
                }

                int shift = BitNTZ(bits);

                elements.Add((byte)((pixels[0] & bits) >> shift));
            }

            var color = new Color();

            if (_supportedFormats.Contains(bitmap.Format))
            {
                color.B = elements[0];
                color.G = (elements.Count >= 2) ? elements[1] : elements[0];
                color.R = (elements.Count >= 3) ? elements[2] : elements[0];
                color.A = 0xFF; // elements[3];
            }
            else if (_supportedIndexFormats.Contains(bitmap.Format))
            {
                color = bitmap.Palette.Colors[elements[0]];
                color.A = 0xFF;
            }
            else
            {
                Debug.WriteLine("GetOneColor: No support format: " + bitmap.Format.ToString());
                color = Colors.Black;
            }

            return color;
        }

        /// <summary>
        /// 半透明画像であるか判定
        /// </summary>
        /// <param name="bitmap"></param>
        /// <returns></returns>
        public static bool? HasAlpha(this BitmapSource bitmap)
        {
            // DelayCreation などでフォーマットが確定していない状態。
            if (bitmap.Format.ToString() == _defaultFormatLabel)
            {
                return null;
            }

            return _supportedAlphaFormats.Contains(bitmap.Format) || bitmap.Palette?.Colors.Any(e => e.A < 0xff) == true;
        }
    }
}

﻿using System.Windows.Media;

namespace NeeView
{
    public class ImageInfo
    {
        public int PixelWidth { get; init; }
        public int PixelHeight { get; init; }
        public PixelFormat Format { get; init; } = PixelFormats.Bgra32;
        public int BitsPerPixel { get; init; } = 32;
        public int FrameCount { get; init; } = 1;
        public double DpiX { get; init; } = 96.0;
        public double DpiY { get; init; } = 96.0;
        public double Width => PixelWidth * 96.0 / DpiX;
        public double Height => PixelHeight * 96.0 / DpiY;
        public bool HasAlpha { get; init; }
    }
}

﻿using PhotoSauce.MagicScaler;
using System;
using System.IO;
using System.Threading;
using System.Windows;
using System.Windows.Media.Imaging;

namespace NeeView
{
    public class MagicScalerBitmapDecoder : IBitmapDecoder
    {
        static MagicScalerBitmapDecoder()
        {
            CodecManager.Configure(codecs =>
            {
                codecs.Clear();
                codecs.UseWicCodecs(WicCodecPolicy.Microsoft);
            });
        }


        public string Name => "PhotoSauce.MagicScaler";

        public bool CheckFormat(Stream stream)
        {
            // NOTE: すべての形式を受け入れる
            return true;
        }

        // 注意: sourceは上書きされます
        // TODO: ↑よろしくない
        private static ProcessImageSettings CreateSetting(Size size, string mimeType, ProcessImageSettings? source)
        {
            var setting = source ?? new ProcessImageSettings();

            // width か height を0にすると、アスペクト比を維持したサイズで変換する
            setting.Width = size.IsEmpty ? 0 : Convert.ToInt32(size.Width);
            setting.Height = size.IsEmpty ? 0 : Convert.ToInt32(size.Height);
            setting.ResizeMode = (setting.Width == 0 || setting.Height == 0) ? CropScaleMode.Crop : CropScaleMode.Stretch;
            setting.Anchor = (setting.ResizeMode == CropScaleMode.Crop) ? CropAnchor.Left | CropAnchor.Top : CropAnchor.Center;

            setting.TrySetEncoderFormat(mimeType);

            return setting;
        }

        public BitmapSource Create(Stream stream, BitmapInfo? info, Size size, CancellationToken token)
        {
            return Create(stream, info, size, null);
        }

        public BitmapSource Create(Stream stream, BitmapInfo? info, Size size, ProcessImageSettings? setting)
        {
            ////Debug.WriteLine($"MagicScalerImage: {size.Truncate()}");

            stream.Seek(0, SeekOrigin.Begin);

            using (var ms = new MemoryStream())
            {
                setting = CreateSetting(size, ImageMimeTypes.Bmp, setting);
                MagicImageProcessor.ProcessImage(stream, ms, setting);

                ms.Seek(0, SeekOrigin.Begin);
                var bitmap = new BitmapImage();
                bitmap.BeginInit();
                bitmap.CacheOption = BitmapCacheOption.OnLoad;
                bitmap.StreamSource = ms;
                bitmap.EndInit();
                bitmap.Freeze();

                return bitmap;
            }
        }

        public void CreateImage(Stream stream, BitmapInfo? info, Stream outStream, Size size, BitmapImageFormat format, int quality, CancellationToken token)
        {
            token.ThrowIfCancellationRequested();
            CreateImage(stream, info, outStream, size, format, quality, null);
        }

        public void CreateImage(Stream stream, BitmapInfo? info, Stream outStream, Size size, BitmapImageFormat format, int quality, ProcessImageSettings? setting)
        {
            ////Debug.WriteLine($"MagicScalerImage: {size.Truncate()}");

            stream.Seek(0, SeekOrigin.Begin);

            setting = CreateSetting(size, CreateFormat(format), setting);

            if (format == BitmapImageFormat.Jpeg)
            {
                setting.EncoderOptions = new JpegEncoderOptions(quality, JpegEncoderOptions.Default.Subsample, JpegEncoderOptions.Default.SuppressApp0);
            }

            MagicImageProcessor.ProcessImage(stream, outStream, setting);
        }

        private static string CreateFormat(BitmapImageFormat format)
        {
            return format switch
            {
                BitmapImageFormat.Png => ImageMimeTypes.Png,
                _ => ImageMimeTypes.Jpeg,
            };
        }

    }

}

﻿using NeeLaboratory.ComponentModel;
using NeeLaboratory.Generators;
using NeeView.Collections.Generic;
using System;
using System.Collections.Generic;
using System.ComponentModel;
using System.Diagnostics;
using System.Linq;

namespace NeeView
{
    public partial class Book : IDisposable, IBook
    {
        public static Book? Default { get; private set; }

        private readonly BookSource _source;
        private BookSettingConfig _setting;
        private readonly BookPageMarker _marker;
        private readonly string _sourcePath;
        private readonly BookLoadOption _loadOption;
        private readonly BookAddress _address;
        private List<Page> _currentPages = new();
        private readonly DisposableCollection _disposables = new();

        public Book(BookAddress address, BookSource source, BookMemento memento, BookLoadOption option, bool isNew, ArchiveHint archiveHint)
        {
            Book.Default = this;

            this.Memento = memento.Clone();
            this.Memento.IsRecursiveFolder = source.IsRecursiveFolder;
            this.Memento.SortMode = source.Pages.SortMode;

            _address = address;
            _source = source;
            _sourcePath = address.SourcePath?.SimplePath ?? "";
            _marker = new BookPageMarker(_source);
            _loadOption = option;

            var currentMemento = this.Memento.Clone();
            AttachBookSetting(currentMemento.ToBookSetting());
            Debug.Assert(_setting != null);

            _source.Pages.PagesSorted += (s, e) => PagesChanged?.Invoke(s, e);

            IsNew = isNew;
            ArchiveHint = archiveHint;

            _disposables.Add(_source);

            _disposables.Add(Config.Current.Book.SubscribePropertyChanged(nameof(BookConfig.FolderSortOrder),
                (s, e) => _source.Pages.UpdatePagesAsync()
            ));
        }



        [Subscribable]
        public event EventHandler? PagesChanged;

        [Subscribable]
        public event EventHandler<CurrentPageChangedEventArgs>? CurrentPageChanged;


        public BookSource Source => _source;
        public BookPageCollection Pages => _source.Pages;
        IReadOnlyList<Page> IBook.Pages => _source.Pages;


        public IReadOnlyList<Page> CurrentPages => _currentPages;
        public Page? CurrentPage => _currentPages.FirstOrDefault();
        public BookPageMarker Marker => _marker;
        public BookMemoryService BookMemoryService => _source.BookMemoryService;
        public BookAddress BookAddress => _address;
        public string Path => _source.Path;
        public string SourcePath => _sourcePath;
        public bool IsMedia => _source.IsMedia;
        public bool IsPlaylist => _source.IsPlaylist;
        public bool IsTemporary => _source.Path.StartsWith(Temporary.Current.TempDirectory, StringComparison.Ordinal);
        public PageSortModeClass PageSortModeClass => IsPlaylist ? PageSortModeClass.WithEntry : PageSortModeClass.Normal;
        public BookLoadOption LoadOption => _loadOption;

        // はじめて開く本
        public bool IsNew { get; private set; }

        // 見つからなかった開始ページ名。通知用。
        // TODO: 不要？
        public string? NotFoundStartPage { get; private set; }

        // 開始ページ
        // TODO: 再読込時に必要だが、なくすことできそう？
        public string? StartEntry { get; private set; }

        public bool IsKeepHistoryOrder => (_loadOption & BookLoadOption.KeepHistoryOrder) == BookLoadOption.KeepHistoryOrder;

        /// <summary>
        /// 初期ページ座標
        /// </summary>
        public DirectionalPagePosition StartPosition { get; private set; } = new();

        /// <summary>
        /// 初期Memento
        /// </summary>
        public BookMemento Memento { get; private set; }

        /// <summary>
        /// 設定
        /// </summary>
        public BookSettingConfig Setting => _setting;

        /// <summary>
        /// アーカイブヒント。再読み込みのときに使用される
        /// </summary>
        public ArchiveHint ArchiveHint { get; private set; }


        public void AttachBookSetting(BookSettingConfig setting)
        {
            if (_disposedValue) return;

            DetachBookSetting();

            // 新しい設定の反映
            _setting = setting;
            _setting.PropertyChanged += Setting_PropertyChanged;
            _source.IsRecursiveFolder = _setting.IsRecursiveFolder;
            _source.Pages.SortMode = _setting.SortMode;
        }

        private void DetachBookSetting()
        {
            if (_setting is null) return;

            _setting.PropertyChanged -= Setting_PropertyChanged;
        }

        private void Setting_PropertyChanged(object? sender, PropertyChangedEventArgs e)
        {
            if (_disposedValue) return;
            if (sender is not BookSettingConfig setting) return;

            var isAll = string.IsNullOrEmpty(e.PropertyName);
            if (isAll || e.PropertyName == nameof(setting.IsRecursiveFolder))
            {
                _source.IsRecursiveFolder = setting.IsRecursiveFolder;
            }
            if (isAll || e.PropertyName == nameof(setting.SortMode))
            {
                _source.Pages.SortMode = setting.SortMode;
            }
        }

        public void SetStartPage(object? sender, BookStartPage startPage)
        {
            if (_disposedValue) return;

            // スタートページ取得
            PagePosition position = _source.Pages.FirstPosition();
            int direction = 1;
            if (startPage.StartPageType == BookStartPageType.FirstPage)
            {
                position = _source.Pages.FirstPosition();
                direction = 1;
            }
            else if (startPage.StartPageType == BookStartPageType.LastPage)
            {
                position = _source.Pages.LastPosition();
                direction = -1;
            }
            else
            {
                int index = !string.IsNullOrEmpty(startPage.PageName) ? _source.Pages.FindIndex(e => e.EntryName == startPage.PageName) : 0;
                if (index < 0)
                {
                    this.NotFoundStartPage = startPage.PageName;
                }
                position = index >= 0 ? new PagePosition(index, 0) : _source.Pages.FirstPosition();
                direction = 1;

                // 最終ページリセット
                // NOTE: ワイドページ判定は行わないため、2ページモードの場合に不正確な場合がある
                int lastPageOffset = (Config.Current.GetFramePageSize(_setting.PageMode) == 2 && !_setting.IsSupportedSingleLastPage) ? 1 : 0;
                if (startPage.IsResetLastPage && index >= _source.Pages.LastPosition().Index - lastPageOffset)
                {
                    position = _source.Pages.FirstPosition();
                }
            }

            // 開始ページ記憶
            this.StartEntry = _source.Pages.Count > 0 ? _source.Pages[position.Index].EntryName : null;

            //this.Memento.Page = this.StartEntry ?? "";
            var page = _source.Pages.Count > 0 ? _source.Pages[position.Index] : null;
            if (page is not null)
            {
                SetCurrentPages(new[] { page });
            }

            // 初期ページ設定 
            StartPosition = new DirectionalPagePosition(position, direction);
        }

        public void Start()
        {
            if (_disposedValue) return;

            // TODO: スタートページへ移動
            //_controller.Start();
        }


        public void SetCurrentPages(IEnumerable<Page> pages)
        {
            if (_disposedValue) return;
            if (_currentPages.SequenceEqual(pages)) return;

            var oldPages = _currentPages;
            _currentPages = pages.ToList();

            var eventArgs = new CurrentPageChangedEventArgs(_currentPages, oldPages);
            CurrentPageChanged?.Invoke(this, eventArgs);
        }


        #region IDisposable Support
        private bool _disposedValue = false;

        public bool IsDisposed => _disposedValue;

        protected virtual void Dispose(bool disposing)
        {
            if (!_disposedValue)
            {
                if (disposing)
                {
                    DetachBookSetting();

                    if (Book.Default == this)
                    {
                        Book.Default = null;
                    }

                    _disposables.Dispose();
                }

                _disposedValue = true;
            }
        }

        public void Dispose()
        {
            Dispose(true);
            GC.SuppressFinalize(this);
        }
        #endregion

        #region Memento

        // bookの設定を取得する
        public BookMemento CreateMemento()
        {
            var memento = new BookMemento
            {
                Path = _source.Path,
                Page = this.CurrentPage?.EntryName ?? "",

                PageMode = _setting.PageMode,
                BookReadOrder = _setting.BookReadOrder,
                IsSupportedDividePage = _setting.IsSupportedDividePage,
                IsSupportedSingleFirstPage = _setting.IsSupportedSingleFirstPage,
                IsSupportedSingleLastPage = _setting.IsSupportedSingleLastPage,
                IsSupportedWidePage = _setting.IsSupportedWidePage,
                IsRecursiveFolder = _source.IsRecursiveFolder,
                SortMode = _source.Pages.SortMode,
                SortSeed = _source.Pages.SortSeed,
                AutoRotate = _setting.AutoRotate,
                BaseScale = _setting.BaseScale,
            };

            return memento;
        }

        #endregion
    }


    public class DirectionalPagePosition
    {
        public DirectionalPagePosition() : this(PagePosition.Zero, 1)
        {
        }

        public DirectionalPagePosition(PagePosition position, int direction)
        {
            Debug.Assert(!position.IsEmpty());
            Debug.Assert(direction is -1 or +1);
            Position = position;
            Direction = direction == -1 ? -1 : +1;
        }

        public PagePosition Position { get; init; }
        public int Direction { get; init; }
    }


    public class CurrentPageChangedEventArgs : EventArgs
    {
        public CurrentPageChangedEventArgs(List<Page> newValue, List<Page> oldValue)
        {
            NewValue = newValue;
            OldValue = oldValue;
        }

        public List<Page> NewValue { get; init; }
        public List<Page> OldValue { get; init; }

        public bool IsTopPageChanged => NewValue.FirstOrDefault() != OldValue.FirstOrDefault();
    }
}

﻿using System.Threading;
using System.Threading.Tasks;

namespace NeeView
{
    public static class BookFactory
    {
        public static async ValueTask<Book> CreateAsync(object? sender, BookAddress address, BookCreateSetting setting, BookMemento memento, CancellationToken token)
        {
            token.ThrowIfCancellationRequested();

            var bookSource = await BookSourceFactory.CreateAsync(address, setting, token);

            // NOTE: メディアブック移動で前のブックに戻ったときにフレーム終端から再生させるためのフラグ設定
            // NOTE: 不要な機能と思われるので無効にしておく
#if false
            if (bookSource.IsMedia)
            {
                foreach (var mediaContent in bookSource.Pages.Select(e => e.ContentAccessor).OfType<MediaContent>())
                {
                    mediaContent.IsLastStart = setting.StartPage.StartPageType == BookStartPageType.LastPage;
                }
            }
#endif

            var book = new Book(address, bookSource, memento, setting.LoadOption, setting.IsNew, setting.ArchiveHint);

            // HACK: Start() で行いたい
            book.SetStartPage(sender, setting.StartPage);

            return book;
        }
    }

}

